// в”Җв”Җв”Җ е…Ёеҹҹијёе…Ҙж·ЁеҢ–пјҲиіҮе®үпјҡйҳІ XSS жіЁе…Ҙпјүв”Җв”Җв”Җ
function sanitizeInput(v){
  if(v==null) return '';
  return String(v).replace(/[<>]/g,function(ch){return ch==='<'?'пјң':'пјһ';}).replace(/javascript:/gi,'').replace(/on\w+=/gi,'');
}
function safeVal(id){
  var el=document.getElementById(id);
  return el?sanitizeInput(el.value):'';
}
