function renderArchGraph(){
  var d=ARCH_DOC;
  var sC={live:'var(--green)',partial:'var(--amber)',planned:'var(--red)'};
  var sBg={live:'var(--green-bg)',partial:'var(--amber-bg)',planned:'var(--red-bg)'};
  var sBd={live:'var(--green-border)',partial:'var(--amber-border)',planned:'var(--red-border)'};
  // зҜҖй»һеҚЎзүҮ
  function node(id,name,icon,status,sub){
    return '<div class="topo-node" onclick="showArchNode(\''+id+'\')" style="border-color:'+sBd[status]+'">'
      +'<div class="topo-dot" style="background:'+sC[status]+'"></div>'
      +'<div class="topo-ico">'+icon+'</div>'
      +'<div class="topo-name">'+name+'</div>'
      +(sub?'<div class="topo-sub">'+sub+'</div>':'')
      +'</div>';
  }
  var h='<div class="topo-map">';
  // еұӨ1пјҡз”ЁжҲ¶иЁӘе•Ҹ
  h+='<div class="topo-layer"><div class="topo-layer-lbl">в‘  з”ЁжҲ¶иЁӘе•ҸеұӨ</div><div class="topo-row">';
  h+=node('user','е№№йғЁ / еҝ—е·Ҙ','рҹ‘Ө','live','Web / жүӢж©ҹ');
  h+=node('lineoa','Line OA','рҹ’¬','partial','еүҚз·ҡеӣһе ұе…ҘеҸЈ');
  h+='</div></div>';
  h+='<div class="topo-arrow">в–ј</div>';
  // еұӨ2пјҡе®үе…ЁиҲҮи·Ҝз”ұ
  h+='<div class="topo-layer topo-dashed" style="border-color:var(--red-border)"><div class="topo-layer-lbl" style="color:var(--red)">в‘Ў е®үе…ЁиҲҮи·Ҝз”ұеұӨ</div><div class="topo-row">';
  h+=node('sec_xss','ијёе…Ҙж·ЁеҢ–','рҹӣЎ','live','XSS йҳІиӯ· esc/sanitize');
  h+=node('sec_role','ж¬ҠйҷҗжҺ§з®Ў','рҹ”‘','partial','еүҚз«Ҝ role В· еҫ…еҫҢз«Ҝй©—иӯү');
  h+=node('sec_ver','зүҲжң¬еӮҷд»Ҫ','рҹ—„','live','жөҒж°ҙиҷҹ + йӣҷжӘ”йӮ„еҺҹ');
  h+='</div></div>';
  h+='<div class="topo-arrow">в–ј</div>';
  // еұӨ3пјҡж ёеҝғйӣІз«ҜжңҚеӢҷпјҲиҷӣз·ҡжЎҶпјү
  h+='<div class="topo-layer topo-dashed" style="border-color:var(--blue-border)"><div class="topo-layer-lbl" style="color:var(--blue)">в‘ў ж ёеҝғжңҚеӢҷеұӨ</div><div class="topo-row">';
  h+=node('dashboard','зёҪжҺ§е„ҖиЎЁжқҝ','рҹ“Ҡ','live','жғ…еўғжЁЎж“¬ В· KPI');
  h+=node('rtsync','еҚіжҷӮиӘҝеәҰдёӯеҸ°','вҡЎ','live','жҙҫе·Ҙ/иӯҰе ұ/SOS/зөҗжЎҲ');
  h+=node('reg','е ұеҗҚе ұеҲ°','рҹ“Ӣ','live','е ұеҲ°+е ұеҗҚйӣҷи»Ң');
  h+=node('monitor','е…ЁеҹҹзӣЈжҺ§','рҹ–ҘпёҸ','live','й«ҳеұӨжұәзӯ–иҰ–ең–');
  h+='</div><div class="topo-row" style="margin-top:8px">';
  h+=node('warehouse','зү©иіҮеҖүе„І','рҹ“Ұ','live','дёүзҙҡйҖ еҶҠиӘҝеәҰ');
  h+=node('shelter','е®үзҪ®/еҖӢжЎҲ/й—ңжҮ·','рҹҸ•пёҸ','live','L3 зҸҫе ҙзҫӨ');
  h+=node('story','ж•…дәӢз·ҡзөҗжЎҲ','рҹ“–','live','жҷӮй–“и»ё+йҒҷжё¬');
  h+='</div></div>';
  h+='<div class="topo-arrow">в–ј</div>';
  // еұӨ4пјҡж•ёж“ҡеҹәзӨҺиЁӯж–ҪпјҲиҷӣз·ҡжЎҶпјү
  h+='<div class="topo-layer topo-dashed" style="border-color:var(--border2)"><div class="topo-layer-lbl" style="color:var(--text3)">в‘Ј ж•ёж“ҡеҹәзӨҺиЁӯж–ҪеұӨ</div><div class="topo-row">';
  h+=node('storage','localStorage','рҹ’ҫ','live','жң¬ж©ҹ+йӣўз·ҡ+йҒҷжё¬');
  h+=node('sheets','GAS + Sheets','рҹ“‘','partial','е ұеҗҚ/еҖӢжЎҲеҫҢз«Ҝ');
  h+=node('firebase','Firebase RTDB','рҹ”Ҙ','planned','еӨҡдәәе…ұз·ЁВ·еҫ…е•ҹз”Ё');
  h+=node('emic','ж”ҝеәң EMIC','рҹҸӣпёҸ','planned','жңӘдҫҶе°ҚжҺҘ');
  h+='</div></div>';
  h+='</div>';
  h+='<div id="arch-node-detail" style="display:none;margin-top:12px;padding:12px 16px;background:var(--bg2);border:1px solid var(--blue-border);border-radius:var(--r-sm)"></div>';
  return h;
}
function showArchNode(id){
  // е…ҲжҹҘ graphNodesпјҢжІ’жңүеҶҚз”Ёе…§е»әиЈңе……иӘӘжҳҺ
  var n=ARCH_DOC.graphNodes.filter(function(x){return x.id===id;})[0];
  var extra={
    sec_xss:{name:'ијёе…Ҙж·ЁеҢ–',status:'live',desc:'esc() еј·еҢ–пјҲеҗ« >гҖҒе–®еј•иҷҹпјү+ sanitizeInput ж·ЁеҢ–е ұеҗҚе§“еҗҚ/д»»еӢҷжЁҷйЎҢ/жү№ж¬ЎдҫҶжәҗзӯүдҪҝз”ЁиҖ…ијёе…ҘпјҢйҳІ XSS жіЁе…ҘгҖӮ'},
    sec_role:{name:'ж¬ҠйҷҗжҺ§з®Ў',status:'partial',desc:'еүҚз«Ҝдҫқи§’иүІ P0~P4 еӢ•ж…ӢйҒ®и”ҪеҖӢиіҮиҲҮжЁЎзө„гҖӮдҪҶ role еҲӨж–·еҸҜиў« console з«„ж”№пјҢйңҖеҫҢз«Ҝй©—иӯүпјҲеҫ…иҫҰ P1пјүгҖӮ'},
    sec_ver:{name:'зүҲжң¬еӮҷд»Ҫ',status:'live',desc:'жҜҸж¬ЎиіҮж–ҷи®ҠжӣҙиҮӘеӢ•йҒһеўһзүҲжң¬жөҒж°ҙиҷҹдёҰеӮҷд»ҪеүҚе…©зүҲпјҢиў«иӘӨи§ёеҸҜдёҖйҚөйӮ„еҺҹпјҢдёҰеҸҜеҢҜеҮә JSON йӣўз·ҡе°ҒеӯҳгҖӮ'}
  };
  if(!n) n=extra[id];
  if(!n) return;
  var lbl={live:'рҹҹў е·Ій–ӢйҖҡ',partial:'рҹҹЎ йғЁеҲҶ/еҫ…иЁӯе®ҡ',planned:'рҹ”ҙ жңӘй–ӢйҖҡ/иҰҸеҠғдёӯ'}[n.status];
  var box=document.getElementById('arch-node-detail');
  if(box){
    box.innerHTML='<div style="font-size:13px;font-weight:700;margin-bottom:4px">'+n.name+' <span style="font-size:11px;font-weight:400;color:var(--text4)">В· '+lbl+'</span></div>'
      +'<div style="font-size:12px;color:var(--text2);line-height:1.7">'+(n.desc||'')+'</div>';
    box.style.display='block';
    box.scrollIntoView({behavior:'smooth',block:'nearest'});
  }
}
