    +'<span style="font-weight:600">з°Ўжҳ“еӨ§еӯ—жЁЎејҸ</span>'
    +'<span style="display:inline-block;width:46px;height:26px;border-radius:13px;background:'+(big?'var(--green)':'var(--border3)')+';position:relative;transition:.2s">'
    +'<span style="position:absolute;top:3px;left:'+(big?'23px':'3px')+';width:20px;height:20px;border-radius:50%;background:#fff;transition:.2s;box-shadow:0 1px 3px rgba(0,0,0,.3)"></span></span></label>';
  html+='</div>';
