  if(!meals||!house||!waste||!photos){ toast('вҡ  и«ӢеЎ«еҜ«жүҖжңүеҝ…еЎ«ж•ёеҖјж¬„дҪҚ'); return; }
  if(parseInt(photos,10)<1){ toast('вҡ  й Ҳйҷ„дёҠиҮіе°‘ 1 ејөзҸҫе ҙз…§зүҮ'); return; }
  var tasks=rtGet('tasks');
  var done=Object.keys(tasks).filter(function(k){return tasks[k].status==='е·Іе®ҢжҲҗ';}).length;
