    +d.catalog.map(function(c){var st=assetStock(c.id);return '<option value="'+c.id+'">'+c.icon+' '+c.name+'пјҲеҸҜеҖҹ '+st.instock+'пјү</option>';}).join('')
    +'</select></div>'
    +'<div><div class="iep-lbl">ж•ёйҮҸ</div><input class="inp" id="ln-qty" type="number" value="1" min="1"></div>'
    +'<div><div class="iep-lbl">йҖҒйҒ”ең°й»һ</div><input class="inp" id="ln-site" placeholder="жў…еұұеңӢе°Ҹ"></div>'
    +'<div><div class="iep-lbl">й җиЁҲжӯёйӮ„</div><input class="inp" id="ln-due" placeholder="06-20"></div>'
    +'<button class="btn btn-blue" onclick="createLoan()">е»әз«ӢиӘҝз”Ёе–®</button>'
    +'</div>'
