    +'</div>';
  html+='<div class="card"><div class="card-title">иӘҝз”Ёе–®еҲ—иЎЁ</div><table class="tbl"><thead><tr><th>е–®иҷҹ</th><th>е“Ғй …</th><th>ж•ёйҮҸ</th><th>йҖҒйҒ”</th><th>з·Ёиҷҹ</th><th>еҖҹеҮә</th><th>жҮүйӮ„</th><th>зӢҖж…Ӣ</th></tr></thead><tbody>';
  for(var i=0;i<d.loans.length;i++){
    var l=d.loans[i];
    var sc=l.status==='е·ІжӯёйӮ„'?'green':l.status==='йҖҫжңҹжңӘйӮ„'?'red':l.status==='йҒӢйҖҒдёӯ'?'blue':'amber';
    html+='<tr><td style="font-family:monospace;font-weight:600">'+l.id+'</td>'
      +'<td style="font-size:11px">'+l.name+'</td>'
      +'<td style="font-family:monospace">'+l.qty+'</td>'
      +'<td style="font-size:11px">'+l.site+'</td>'
      +'<td style="font-family:monospace;font-size:10px">'+l.codes+'</td>'
      +'<td style="font-family:monospace;font-size:10px">'+l.out+'</td>'
      +'<td style="font-family:monospace;font-size:11px;color:'+(l.status==='йҖҫжңҹжңӘйӮ„'?'var(--red)':'inherit')+'">'+l.due+'</td>'
      +'<td><span class="badge badge-'+sc+'">'+l.status+'</span></td>'
      +'</tr>';
  }
  html+='</tbody></table></div>';
  return html;
