function updateLoanHint(){
  var cid=document.getElementById('ln-cat').value;
  var st=assetStock(cid);
  var cat=DATA.assets.catalog.find(function(c){return c.id===cid;});
  var el=document.getElementById('ln-hint');
  if(el&&cat) el.innerHTML='рҹ“Ұ '+cat.name+'пјҡзёҪж•ё '+cat.total+' В· еңЁеә«еҸҜеҖҹ <b style="color:var(--green)">'+st.instock+'</b> В· еҖҹеҮә '+st.out+' В· з¶ӯдҝ® '+st.repair;
}
function createLoan(){
  var cid=document.getElementById('ln-cat').value;
  var qty=parseInt(document.getElementById('ln-qty').value,10)||1;
  var site=(document.getElementById('ln-site').value||'еүҚз·ҡ').trim();
  var due=(document.getElementById('ln-due').value||'жңӘе®ҡ').trim();
  var st=assetStock(cid);
  var cat=DATA.assets.catalog.find(function(c){return c.id===cid;});
  if(qty>st.instock){ toast('вҡ  еңЁеә«дёҚи¶іпјҡ'+cat.name+' еғ…еү© '+st.instock+' '+cat.unit); return; }
  var d=DATA.assets;
  var id='LN-'+String(++d.seq).padStart(3,'0');
  // assign codes: find next available block
  var used=0;
  d.loans.forEach(function(l){if(l.cat===cid){var m=l.codes.match(/~(\d+)/);if(m)used=Math.max(used,parseInt(m[1],10));}});
  var start=used+1, end=used+qty;
  var pad=function(n){return String(n).padStart(3,'0');};
  var codes=cat.code+'-'+pad(start)+(qty>1?'~'+pad(end):'');
  d.loans.unshift({id:id,cat:cid,name:cat.name,qty:qty,site:site,borrower:site,out:new Date().toLocaleString('zh-TW',{month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}).replace(/\//g,'-'),due:due,back:'',status:'йҒӢйҖҒдёӯ',codes:codes});
  logSys('ok','гҖҗиіҮз”ўгҖ‘иӘҝз”Ёе–® '+id+'пјҡ'+cat.name+' Г—'+qty+'пјҲ'+codes+'пјүвҶ’ '+site+'пјҢе·ІжүЈеә«еӯҳйҖІе…ҘйҒӢйҖҒ');
  toast('рҹ“Ө '+id+' е·Іе»әз«ӢпјҢ'+cat.name+' Г—'+qty+' йҖІе…ҘйҒӢйҖҒ');
  renderAssets();
}
