// в”Җв”Җ ж•…дәӢз·ҡзөҗжЎҲе ұе‘Ҡ MVP в”Җв”Җ
var _lastStoryline=null;
// в”Җв”Җ жҮүи®Ҡе ҙж¬ЎпјҲsessionпјүиҲҮйҒҷжё¬ в”Җв”Җ
var SESSION=null; // {id, scenario, level, startTime, startTs, errors:[], rapidClicks:[]}
function startSession(scenario,level){
  SESSION={
    id:'S'+Date.now(),
    scenario:scenario||'жңӘжҢҮе®ҡ',
    level:level||'',
    startTime:new Date().toLocaleString('zh-TW'),
    startTs:Date.now(),
    errors:[],
    rapidClicks:[]
  };
  try{ localStorage.setItem('drms_session',JSON.stringify(SESSION)); }catch(e){}
  logSys('info','рҹ“Қ жҮүи®Ҡе ҙж¬Ўй–Ӣе§Ӣпјҡ'+SESSION.id+'пјҲ'+SESSION.scenario+(level?(' В· '+level):'')+'пјү');
}
function endSession(){
  if(!SESSION) return null;
  SESSION.endTime=new Date().toLocaleString('zh-TW');
  SESSION.endTs=Date.now();
  SESSION.durationMin=Math.round((SESSION.endTs-SESSION.startTs)/60000);
  try{ localStorage.setItem('drms_session_last',JSON.stringify(SESSION)); }catch(e){}
  var s=SESSION;
  logSys('ok','рҹҸҒ жҮүи®Ҡе ҙж¬Ўзөҗжқҹпјҡ'+s.id+'пјҢжӯ·жҷӮ '+s.durationMin+' еҲҶйҗҳ');
  return s;
}
function loadSession(){
  try{ var raw=localStorage.getItem('drms_session'); if(raw) SESSION=JSON.parse(raw); }catch(e){}
}
// йҢҜиӘӨйҒҷжё¬пјҡиў« logSys е‘јеҸ«
function telemetryLog(level,msg){
  if(!SESSION) return;
  if(level==='err'||level==='warn'){
    SESSION.errors.push({time:new Date().toLocaleTimeString('zh-TW'),level:level,msg:msg});
    if(SESSION.errors.length>200) SESSION.errors.shift();
    try{ localStorage.setItem('drms_session',JSON.stringify(SESSION)); }catch(e){}
  }
}
// йҮҚиӨҮй»һж“ҠеҒөжё¬пјҲUX еҚЎй “иЁҠиҷҹпјү
var _clickTrack={};
function trackRapidClick(label){
  if(!SESSION) return;
  var now=Date.now();
  var rec=_clickTrack[label]||{count:0,first:now};
  if(now-rec.last< 800){ // 800ms е…§йҖЈй»һ
    rec.count++;
    if(rec.count===3){ // йҖЈй»һ 3 ж¬ЎжүҚиЁҳпјҢйҒҝе…ҚйӣңиЁҠ
      SESSION.rapidClicks.push({time:new Date().toLocaleTimeString('zh-TW'),target:label,count:rec.count});
      if(SESSION.rapidClicks.length>100) SESSION.rapidClicks.shift();
      try{ localStorage.setItem('drms_session',JSON.stringify(SESSION)); }catch(e){}
    }
  } else {
    rec.count=1;
  }
  rec.last=now;
  _clickTrack[label]=rec;
}
function buildStorylineData(){
  // еҗҲдҪө auditLogпјҲRTDBпјүжҲҗжҷӮй–“еәҸеҲ—
  var log=rtGet('auditLog')||{};
  var keys=Object.keys(log);
  var events=[];
  for(var i=0;i<keys.length;i++){
    var e=log[keys[i]];
    if(e&&e.time) events.push({time:e.time,actor:e.actor||'зі»зөұ',action:e.action||'ж“ҚдҪң',detail:e.detail||''});
  }
  // дҫқжҷӮй–“еӯ—дёІжҺ’еәҸпјҲж јејҸ MM/DD HH:MM:SSпјү
  events.sort(function(a,b){ return a.time<b.time?-1:(a.time>b.time?1:0); });
  return events;
}
function classifyEvent(action){
  // дәӢд»¶еҲҶйЎһ вҶ’ ж•ҳдәӢиӘһж°ЈиҲҮең–зӨә
  var map={
    'жүӢеӢ•иӯҰе ұ':{icon:'рҹҡЁ',tone:'critical',verb:'зҷјеёғз·ҠжҖҘиӯҰе ұ'},
    'SOSжұӮж•‘':{icon:'рҹҶҳ',tone:'critical',verb:'еүҚз·ҡеӮіеҮәжұӮж•‘иЁҠиҷҹ'},
    'SOSи§ЈйҷӨ':{icon:'вң…',tone:'good',verb:'жұӮж•‘и§ЈйҷӨ'},
    'з–ІеӢһиӯҰзӨә':{icon:'рҹҳҙ',tone:'warn',verb:'и§ёзҷјз–ІеӢһдҝқиӯ·'},
    'жҙҫе·Ҙ':{icon:'рҹ“Ӣ',tone:'info',verb:'жҢҮжҙҫд»»еӢҷ'},
    'зөҗжЎҲ':{icon:'рҹҸҒ',tone:'good',verb:'е®ҢжҲҗд»»еӢҷзөҗжЎҲ'},
    'жҺЁж’ӯ':{icon:'рҹ“Ө',tone:'info',verb:'зҷјйҖҒжҺЁж’ӯ'},
    'ж ёйҠ·':{icon:'рҹ“Ұ',tone:'info',verb:'ж ёйҠ·иЈқеӮҷ'}
  };
  for(var k in map){ if(action.indexOf(k)>=0) return map[k]; }
  return {icon:'вҖў',tone:'info',verb:action};
}
function genStoryline(){
  var events=buildStorylineData();
  var out=document.getElementById('storyline-out'); if(!out) return;
  if(!events.length){
    out.innerHTML='<div style="color:var(--text4);text-align:center;padding:16px 0">жң¬ж¬ЎжҮүи®Ҡе°ҡз„Ўж“ҚдҪңи»Ңи·ЎпјҢз„Ўжі•з”ҹжҲҗж•…дәӢз·ҡгҖӮ</div>';
    return;
  }
  // зөұиЁҲж‘ҳиҰҒ
  var stat={critical:0,warn:0,good:0,info:0};
  for(var i=0;i<events.length;i++){ stat[classifyEvent(events[i].action).tone]++; }
  var t0=events[0].time, tN=events[events.length-1].time;
  // ж•ҳдәӢй ӯ
  var sess=SESSION||(function(){try{return JSON.parse(localStorage.getItem('drms_session_last'));}catch(e){return null;}})();
  var html='<div style="background:var(--bg3);border-radius:var(--r-sm);padding:12px 14px;margin-bottom:14px">';
  html+='<div style="font-size:13px;font-weight:700;margin-bottom:4px">рҹ“Ӣ жҮүи®Ҡж‘ҳиҰҒ</div>';
  if(sess){
    html+='<div style="font-size:11px;color:var(--text2);margin-bottom:4px">е ҙж¬Ў <span style="font-family:monospace">'+sess.id+'</span> В· '+sess.scenario+(sess.level?(' В· '+sess.level):'')+'</div>';
  }
  html+='<div style="font-size:11px;color:var(--text2)">жңҹй–“ '+t0+' иҮі '+tN+' В· е…ұ '+events.length+' зӯҶж“ҚдҪңи»Ңи·Ў</div>';
  // зі»зөұеҒҘеә·еәҰпјҲйҢҜиӘӨиҒҡеҗҲ + еҚЎй “й»һпјү
  if(sess){
    var errCnt=(sess.errors||[]).length;
    var clickCnt=(sess.rapidClicks||[]).length;
    // й«ҳй »йҢҜиӘӨжҺ’иЎҢ
    var errRank={};
    (sess.errors||[]).forEach(function(e){ var k=e.msg.slice(0,20); errRank[k]=(errRank[k]||0)+1; });
    var topErr=Object.keys(errRank).sort(function(a,b){return errRank[b]-errRank[a];}).slice(0,3);
    html+='<div style="display:flex;gap:8px;margin-top:8px;flex-wrap:wrap">';
    html+='<span class="badge" style="background:'+(errCnt?'var(--red-bg)':'var(--green-bg)')+';color:'+(errCnt?'var(--red)':'var(--green)')+'">вҡҷ зі»зөұз•°еёё '+errCnt+'</span>';
    html+='<span class="badge" style="background:'+(clickCnt?'var(--amber-bg)':'var(--bg2)')+';color:'+(clickCnt?'var(--amber)':'var(--text3)')+'">рҹ–ұ UX еҚЎй “ '+clickCnt+'</span>';
    html+='</div>';
    if(topErr.length){
      html+='<div style="margin-top:8px;font-size:10px;color:var(--text4)">й«ҳй »з•°еёёпјҡ';
      html+=topErr.map(function(k){return esc(k)+'пјҲ'+errRank[k]+'пјү';}).join('гҖҒ');
      html+='</div>';
    }
    if(clickCnt){
      var clkTargets={};
      (sess.rapidClicks||[]).forEach(function(c){ clkTargets[c.target]=(clkTargets[c.target]||0)+1; });
      var topClk=Object.keys(clkTargets).sort(function(a,b){return clkTargets[b]-clkTargets[a];}).slice(0,3);
      html+='<div style="margin-top:4px;font-size:10px;color:var(--text4)">еҚЎй “зҶұй»һпјҡ'+topClk.map(function(t){return esc(t)+'пјҲ'+clkTargets[t]+'пјү';}).join('гҖҒ')+'</div>';
    }
  }
  html+='<div style="display:flex;gap:10px;margin-top:8px;flex-wrap:wrap">';
  if(stat.critical) html+='<span class="badge" style="background:var(--red-bg);color:var(--red)">рҹҡЁ з·ҠжҖҘдәӢд»¶ '+stat.critical+'</span>';
  if(stat.warn) html+='<span class="badge" style="background:var(--amber-bg);color:var(--amber)">вҡ  иӯҰзӨә '+stat.warn+'</span>';
  if(stat.good) html+='<span class="badge" style="background:var(--green-bg);color:var(--green)">вң… е®ҢжҲҗ '+stat.good+'</span>';
  html+='<span class="badge" style="background:var(--bg2);color:var(--text3)">рҹ“қ ж“ҚдҪң '+stat.info+'</span>';
  html+='</div></div>';
  // жҷӮй–“и»ё
  var toneColor={critical:'var(--red)',warn:'var(--amber)',good:'var(--green)',info:'var(--text3)'};
  html+='<div style="position:relative;padding-left:8px">';
  for(var j=0;j<events.length;j++){
    var ev=events[j], cl=classifyEvent(ev.action);
    var col=toneColor[cl.tone];
    html+='<div style="display:flex;gap:10px;padding:7px 0;border-left:2px solid '+col+';padding-left:12px;margin-left:4px">';
    html+='<div style="flex-shrink:0;font-size:14px">'+cl.icon+'</div>';
    html+='<div style="flex:1"><div style="font-size:11px;color:var(--text4);font-family:monospace">T '+ev.time+'</div>';
    html+='<div style="font-size:12px"><b style="color:'+col+'">'+ev.actor+'</b> '+cl.verb;
    if(ev.detail) html+='<span style="color:var(--text2)"> вҖ” '+esc(ev.detail)+'</span>';
    html+='</div></div></div>';
  }
  html+='</div>';
  out.innerHTML=html;
  // жҡ«еӯҳдҫӣеҢҜеҮә
  _lastStoryline={generated:new Date().toISOString(),session:sess||null,period:{from:t0,to:tN},summary:stat,telemetry:sess?{errors:sess.errors||[],rapidClicks:sess.rapidClicks||[]}:null,events:events};
}
function exportStoryline(){
  if(!_lastStoryline){ toast('и«Ӣе…Ҳз”ҹжҲҗжҷӮй–“и»ё'); return; }
  var blob=new Blob([JSON.stringify(_lastStoryline,null,2)],{type:'application/json'});
  var url=URL.createObjectURL(blob);
  var a=document.createElement('a');
  var stamp=new Date().toISOString().slice(0,10);
  a.href=url; a.download='DRMS_зөҗжЎҲж•…дәӢз·ҡ_'+stamp+'.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
  toast('рҹ“Ө ж•…дәӢз·ҡе°Ғеӯҳе·ІеҢҜеҮәпјҲеҸҜдҪңжј”з·ҙеҠҮжң¬зҙ жқҗпјү');
}
