function returnAsset(id,intact){
  var d=DATA.assets;
  var l=d.loans.find(function(x){return x.id===id;});
  if(!l) return;
  l.status='е·ІжӯёйӮ„';
  l.back=new Date().toLocaleString('zh-TW',{month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}).replace(/\//g,'-');
  if(!intact){
    var cat=d.catalog.find(function(c){return c.id===l.cat;});
    var n=prompt('жҗҚеЈһж•ёйҮҸпјҲе…ұ '+l.qty+' '+(cat?cat.unit:'д»¶')+'пјүпјҡ','1');
    var dmg=Math.min(parseInt(n,10)||0,l.qty);
    if(cat&&dmg>0){ cat.repair+=dmg; }
    logSys('warn','гҖҗиіҮз”ўгҖ‘'+id+' '+l.name+' жӯёйӮ„пјҢ'+dmg+' д»¶жҗҚеЈһиҪүз¶ӯдҝ®пјҢ'+(l.qty-dmg)+' д»¶еӣһеә«');
    toast('рҹ”§ '+id+' е·ІжӯёйӮ„пјҢ'+dmg+' д»¶йҖІз¶ӯдҝ®');
  } else {
    logSys('ok','гҖҗиіҮз”ўгҖ‘'+id+' '+l.name+' Г—'+l.qty+' е®ҢеҘҪжӯёйӮ„пјҢе·Іеӣһеә«еҸҜеҶҚеҖҹ');
    toast('вң… '+id+' е®ҢеҘҪжӯёйӮ„пјҢеӣһеә«');
  }
  renderAssets();
}
