var SORT_TAB='board';
function setSortTab(t){
  SORT_TAB=t;
  ['board','intake','sort','discard','repack'].forEach(function(x){
    var b=document.getElementById('stab-'+x);
    if(b){b.className=(x===t)?'btn btn-blue':'btn btn-ghost';}
  });
  var tid=document.getElementById('res-sorting')?'res-sorting':'sorting-content';
  renderSorting(tid);
}
function renderSorting(targetId){
  var el=document.getElementById(targetId||'sorting-content'); if(!el) return;
  if(SORT_TAB==='board') el.innerHTML=renderSortBoard();
  else if(SORT_TAB==='intake') el.innerHTML=renderSortIntake();
  else if(SORT_TAB==='sort') el.innerHTML=renderSortStation();
  else if(SORT_TAB==='discard') el.innerHTML=renderSortDiscard();
  else if(SORT_TAB==='repack') el.innerHTML=renderSortRepack();
}
function renderSortBoard(){
  var d=DATA.sorting;
  var totalBoxes=d.intake.reduce(function(a,b){return a+b.boxes;},0);
  var waiting=d.intake.filter(function(b){return b.status==='еҫ…жӢҶ';}).length;
  var total=d.sorted.ok+d.sorted.pending+d.sorted.discard;
  var discardRate=total?Math.round(d.sorted.discard/total*100):0;
  var html=makeStatGrid([
    {lbl:'д»Ҡж—Ҙж”¶д»¶',val:totalBoxes,sub:d.intake.length+' жү№ж¬Ў',color:'blue'},
    {lbl:'е·ІеҲҶйЎһ',val:d.sorted.ok,sub:'еҗҲж јд»¶ж•ё',color:'green'},
    {lbl:'е ұе»ўзҺҮ',val:discardRate+'%',sub:d.sorted.discard+' д»¶е ұе»ў',color:discardRate>15?'red':'amber'},
    {lbl:'жЁҷжә–еҢ…з”ўеҮә',val:d.repacks.reduce(function(a,r){return a+r.done;},0),sub:'д»Ҡж—Ҙе®ҢжҲҗ',color:'purple'},
  ]);
  if(waiting>=2){
    html+='<div style="padding:10px 14px;background:var(--amber-bg);border:1px solid var(--amber-border);border-radius:var(--r-sm);margin-bottom:14px;font-size:12px;color:var(--amber);font-weight:600">вҡ  з“¶й ёиӯҰзӨәпјҡжҡ«еӯҳеҚҖе Ҷз©Қ '+waiting+' жү№ж¬Ўеҫ…жӢҶпјҢе»әиӯ°еҠ жҙҫжӢҶз®ұзө„дәәеҠӣ</div>';
  }
  html+='<div class="card"><div class="card-title">еҗ„з«ҷиҷ•зҗҶйҖҹеәҰпјҲд»Ҡж—Ҙпјү</div>';
  for(var i=0;i<d.stations.length;i++){
    var st=d.stations[i];
    var pct=Math.min(Math.round(st.doneToday/(st.workers*60)*100),100);
    html+='<div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">'
      +'<span style="font-size:16px;width:24px">'+st.icon+'</span>'
      +'<span style="width:64px;font-size:12px;font-weight:600">'+st.name+'</span>'
      +'<span style="font-size:10px;color:var(--text4);width:44px">'+st.workers+' дәә</span>'
      +'<div style="flex:1;background:var(--bg3);border-radius:4px;height:8px;overflow:hidden">'
      +'<div style="width:'+pct+'%;height:100%;background:'+(pct>80?'var(--red)':pct>50?'var(--amber)':'var(--green)')+'"></div></div>'
      +'<span style="font-size:11px;font-family:monospace;width:70px;text-align:right">'+st.doneToday+' '+st.unit+'</span>'
      +'</div>';
  }
  html+='</div>';
  html+='<div class="card" style="margin-top:12px"><div class="card-title">еҲҶйЎһиҰҸеүҮйҖҹжҹҘ</div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">';
  for(var j=0;j<d.rules.length;j++){
    var rl=d.rules[j];
    html+='<div style="padding:8px 10px;background:var(--bg3);border:1px solid var(--border);border-radius:var(--r-sm);font-size:11px">'
      +'<b>'+rl.icon+' '+rl.cat+'</b> вҶ’ '+rl.autoTo+'<br><span style="color:var(--text4);font-size:10px">'+rl.check+'</span></div>';
  }
  html+='</div></div>';
  return html;
}
