function addIntake(){
  var src=sanitizeInput((document.getElementById('in-source').value||'ж°‘зңҫжҚҗиҙҲ').trim());
  var bx=parseInt(document.getElementById('in-boxes').value,10)||1;
  var nt=(document.getElementById('in-note').value||'').trim();
  var id='B-'+(100+DATA.sorting.intake.length+1);
  DATA.sorting.intake.push({id:id,source:src,boxes:bx,arrived:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'}),status:'еҫ…жӢҶ',note:nt});
  logSys('ok','гҖҗж•ҙзҗҶз«ҷгҖ‘ж–°жү№ж¬Ў '+id+'пјҡ'+src+' '+bx+' з®ұ');
  toast('рҹ“Ҙ жү№ж¬Ў '+id+' е·Ізҷ»иЁҳ');
  renderSorting();
}
