function sortItem(kind){
  var item=(document.getElementById('so-item').value||'жңӘеЎ«е“Ғй …').trim();
  var cat=document.getElementById('so-cat').value;
  var qty=parseInt(document.getElementById('so-qty').value,10)||1;
  var batch=document.getElementById('so-batch').value;
  var d=DATA.sorting;
  if(kind==='ok'){
    d.sorted.ok+=qty;
    logSys('ok','гҖҗеҲҶйЎһгҖ‘'+batch+' '+item+' Г—'+qty+'пјҲ'+cat+'пјүвҶ’ еҗҲж ј');
    toast('вң… '+item+' еҗҲж је…ҘеҲҶйЎһеҚҖ');
  } else if(kind==='pending'){
    d.sorted.pending+=qty;
    d.pendingItems.push({id:'PD-'+String(d.pendingItems.length+1).padStart(2,'0'),item:item+' Г—'+qty,cat:cat,from:batch,note:'еҝ—е·ҘеҲҶжөҒйҖҒиҰҶж ё'});
    logSys('warn','гҖҗеҲҶйЎһгҖ‘'+batch+' '+item+' вҶ’ еҫ…еҲӨе®ҡдҪҮеҲ—');
    toast('вҡ  '+item+' йҖІеҫ…еҲӨе®ҡ');
  } else {
    var reason=prompt('е ұе»ўеҺҹеӣ пјҲйҒҺжңҹ/з ҙжҗҚ/дёҚжҳҺ/дёҚйҒ©з”Ёпјүпјҡ','йҒҺжңҹ')||'дёҚжҳҺ';
    d.sorted.discard+=qty;
    d.discards.unshift({item:item,cat:cat,qty:qty,reason:reason,time:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'})});
    logSys('warn','гҖҗеҲҶйЎһгҖ‘'+batch+' '+item+' Г—'+qty+' вҶ’ е ұе»ўпјҲ'+reason+'пјү');
    toast('вқҢ '+item+' е·Іе ұе»ўзҷ»иЁҳ');
  }
  document.getElementById('so-item').value='';
  renderSorting();
}
