        +'<span class="badge badge-'+(f.status==='еҫ…еҲҶйЎһ'?'amber':'green')+'" style="font-size:9px;margin-top:3px;display:inline-block">'+(f.status==='еҫ…еҲҶйЎһ'?'еҫ…еҲҶйЎһ':f.category)+'</span>'
