function classifyFile(folderId,fileId,cat){
  if(!cat) return;
  var folder=DATA.drive.folders.find(function(x){return x.id===folderId;});
  if(!folder) return;
  var file=folder.files.find(function(x){return x.id===fileId;});
  if(!file) return;
  file.category=cat; file.status='е·ІеҲҶйЎһ';
  logSys('ok','гҖҗDriveгҖ‘'+file.name+' вҶ’ гҖҢ'+cat+'гҖҚ');
  renderDrive();
}
function autoClassifyAll(){
  var d=DATA.drive; var n=0;
  for(var fi=0;fi<d.folders.length;fi++){
    for(var pi=0;pi<d.folders[fi].files.length;pi++){
      var f=d.folders[fi].files[pi];
      if(f.status==='е·ІеҲҶйЎһ') continue;
      var ctx=f.uploader+' '+d.folders[fi].name+' '+f.name;
      for(var ri=0;ri<d.autoRules.length;ri++){
        var rl=d.autoRules[ri];
        if(ctx.includes(rl.keyword)){f.category=rl.targetCat;f.status='е·ІеҲҶйЎһ';n++;break;}
      }
    }
  }
  renderDrive();
  logSys('ok','гҖҗиҮӘеӢ•еҲҶйЎһгҖ‘'+n+' зӯҶе·ІжӯёйЎһ');
  toast('рҹӨ– иҮӘеӢ•еҲҶйЎһе®ҢжҲҗпјҡ'+n+' зӯҶ');
}
function addAutoRule(){
  var kw=prompt('ијёе…Ҙй—ңйҚөеӯ—пјҲдҫӢеҰӮпјҡеҖ’еЎҢгҖҒз©Қж°ҙпјүпјҡ'); if(!kw||!kw.trim()) return;
  var cat=prompt('е°ҚжҮүеҲҶйЎһпјҡ','зҸҫе ҙзӢҖжіҒ'); if(!cat) return;
  var icons={'зҸҫе ҙзӢҖжіҒ':'рҹҸ ','зү©иіҮзӢҖжіҒ':'рҹ“Ұ','дәәе“ЎеӮ·дәЎ':'рҹҡ‘','ж”¶е®№зӢҖжіҒ':'рҹҸ•','жё…жҺғдҪңжҘӯ':'рҹ§№','е…¶д»–':'рҹ“Ң'};
  var clrs={'зҸҫе ҙзӢҖжіҒ':'blue','зү©иіҮзӢҖжіҒ':'amber','дәәе“ЎеӮ·дәЎ':'red','ж”¶е®№зӢҖжіҒ':'green','жё…жҺғдҪңжҘӯ':'purple','е…¶д»–':'blue'};
  DATA.drive.autoRules.push({keyword:kw.trim(),targetCat:cat,icon:icons[cat]||'рҹ“Ң',color:clrs[cat]||'blue'});
  renderDrive(); toast('вң“ иҰҸеүҮе·Іж–°еўһ');
}
function deleteAutoRule(i){ DATA.drive.autoRules.splice(i,1); renderDrive(); toast('рҹ—‘ иҰҸеүҮе·Із§»йҷӨ'); }
