    +'<div id="loa-status-area" style="font-size:10px;line-height:1.9"></div>'
    +'</div>'
    +'<div class="card" style="margin-top:10px">'
    +'<div class="card-title"><span class="dot blink" style="background:var(--green);margin-right:6px"></span>жҺЁж’ӯзҙҖйҢ„</div>'
    +'<div id="loa-log" style="font-size:10px;line-height:1.9;min-height:40px;color:var(--text3);max-height:120px;overflow-y:auto">зӯүеҫ…ж“ҚдҪң...</div>'
    +'</div>'
    +'</div>'
    // дёӯпјҡеҝ—е·ҘжүӢж©ҹ
    +'<div style="display:flex;justify-content:center">'+makeLoaPhoneShell('vol','loa-phone-vol')+'</div>'
