function loaContainer(){ return document.getElementById('rt-loa-content')||document.getElementById('line-oa-content')||document; }
// в”Җв”Җ жёІжҹ“иҒҠеӨ©ж°ЈжіЎ в”Җв”Җ
function loaRenderChat(){
  var el=loaContainer().querySelector('#loa-chat'); if(!el) return;
  var msgs=LOA_CHAT[LOA_ROLE]||[];
  el.innerHTML = msgs.map(function(m){
    if(m.from==='oa') return loaChatBubbleOA(m);
    return loaChatBubbleUser(m);
  }).join('');
  // жҚІеҲ°еә•
  el.scrollTop = el.scrollHeight;
}

function loaChatBubbleOA(m){
  var bg='#fff'; var color='#222';
  var inner = '<div style="font-size:11px;line-height:1.6;white-space:pre-wrap">'+escHtml(m.text||'')+'</div>';

  if(m.card==='tasks'){
    var tasks=(DATA.tasks&&DATA.tasks.items||[]).slice(0,3);
    inner += tasks.map(function(t){
      return '<div style="margin-top:6px;background:#f5f5f5;border-radius:8px;padding:6px 8px;font-size:10px">'
        +'<b>'+t.id+'</b> '+t.title
        +'<br><span style="color:#888">'+t.assign+' В· '+t.endTime+'</span>'
        +(t.status!=='done'?'<br><button onclick="loaStaffTaskDone(\''+t.id+'\')" style="margin-top:4px;background:#06C755;color:#fff;border:none;border-radius:4px;padding:3px 8px;font-size:10px;cursor:pointer">вң… е®Ңе·Ҙеӣһе ұ</button>':'<br><span style="color:#06C755;font-size:10px">вң“ е·Іе®ҢжҲҗ</span>')
        +'</div>';
    }).join('');
  }
  if(m.card==='supply'){
    var reqs=(DATA.warehouse&&DATA.warehouse.reqs||[]).filter(function(r){return r.status==='еҫ…жҙҫжЎҲ'||r.status==='е·ІжҙҫжЎҲ';}).slice(0,3);
    inner += reqs.map(function(r){
      return '<div style="margin-top:6px;background:#f5f5f5;border-radius:8px;padding:6px 8px;font-size:10px">'
        +'<b style="color:'+(r.prio==='P1'?'#ef4444':'#f59e0b')+'">'+r.prio+'</b> '+r.item+' '+r.qty
        +'<br><span style="color:#888">вҶ’ '+r.site+' В· '+r.due+'</span>'
        +(r.status!=='е·ІйҖҒйҒ”'?'<br><button onclick="loaDriverConfirm(\''+r.id+'\')" style="margin-top:4px;background:#3b82f6;color:#fff;border:none;border-radius:4px;padding:3px 8px;font-size:10px;cursor:pointer">вң… е·ІеҲ°иІЁ</button>':'')
        +'</div>';
    }).join('');
  }
  if(m.flex==='rollcall'){
    inner += '<div style="margin-top:8px;display:flex;gap:6px">'
      +'<button onclick="loaVolSafe()" style="flex:1;background:#06C755;color:#fff;border:none;border-radius:8px;padding:8px;font-size:12px;cursor:pointer">вң… жҲ‘е®үе…Ё</button>'
      +'<button onclick="loaVolSOS()" style="flex:1;background:#ef4444;color:#fff;border:none;border-radius:8px;padding:8px;font-size:12px;cursor:pointer">рҹҶҳ жұӮж•‘</button>'
      +'</div>';
  }
  if(m.flex==='supply_items'){
    inner += '<div style="margin-top:8px;display:flex;flex-direction:column;gap:4px">'
      +['зӨҰжіүж°ҙ','дҫҝз•¶','йҶ«зҷӮиҖ—жқҗ','жҜӣжҜҜ','зҷјйӣ»ж©ҹзҮғжІ№','жё…жҪ”з”Ёе“Ғ'].map(function(item){
        return '<button onclick="loaSupplyPickItem(\''+item+'\')" '
          +'style="background:#f0f0f0;border:1px solid #ddd;border-radius:8px;padding:6px;font-size:11px;cursor:pointer;text-align:left">'+item+'</button>';
      }).join('')
      +'</div>';
  }
  if(m.flex==='supply_qty'){
    inner += '<div style="margin-top:8px;display:flex;gap:4px;flex-wrap:wrap">'
      +['Г—10','Г—20','Г—50','Г—100'].map(function(q){
        return '<button onclick="loaSupplyPickQty(\''+q+'\')" '
          +'style="flex:1;background:#f59e0b;color:#fff;border:none;border-radius:8px;padding:8px;font-size:12px;cursor:pointer">'+q+'</button>';
      }).join('')
      +'</div>';
  }

  return '<div style="display:flex;gap:6px;align-items:flex-start">'
    +'<div style="width:28px;height:28px;background:#06C755;border-radius:50%;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:13px">рҹҸҘ</div>'
    +'<div style="max-width:200px;background:'+bg+';border-radius:0 10px 10px 10px;padding:8px 10px;color:'+color+';box-shadow:0 1px 2px rgba(0,0,0,.1)">'
      +inner
    +'</div></div>';
}

