function getOpsAlerts(){
  var ops=[];
  var now=new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
  var pend=DATA.warehouse.reqs.filter(function(x){return x.status==='еҫ…жҙҫжЎҲ';});
  if(pend.length) ops.push({type:'amber',title:'дҫӣйңҖжҙҫжЎҲеҸ°жңү '+pend.length+' ејөйңҖжұӮе–®еҫ…жҙҫ',desc:pend.map(function(p){return p.id;}).join('гҖҒ')+'пјҲжңҖй«ҳ '+pend[0].prio+'пјү',time:now+' В· зі»зөұиҮӘеӢ•'});
  var low=DATA.field.supplies.filter(function(x){return x.status==='red';});
  if(low.length) ops.push({type:'red',title:'зү©иіҮз·ҠжҖҘзҹӯзјәпјҡ'+low.map(function(x){return x.item;}).join('гҖҒ'),desc:'еә«еӯҳдҪҺж–јйңҖжұӮ 30%пјҢе»әиӯ°и·ЁеҚҖиӘҝж’Ҙ',time:now+' В· зі»зөұиҮӘеӢ•'});
  return ops;
}
function renderAlerts(){
  var a=DATA.alerts;
  var el=document.getElementById('w-alerts-content');
  if(!el) return;
  var html='<div class="card-title"><span class="dot blink" style="background:var(--red);"></span>'+a.title+'</div>';
  var ops=getOpsAlerts();
  for(var oi=0;oi<ops.length;oi++){
    var op=ops[oi];
    html+='<div class="alert-item '+op.type+'" style="border-style:dashed">'
      +'<div class="alert-dot"></div><div>'
      +'<div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:2px">вҡҷ '+op.title+'</div>'
      +'<div style="font-size:11px;color:var(--text2)">'+op.desc+'</div>'
      +'<div style="font-size:10px;color:var(--text4);font-family:monospace;margin-top:2px">'+op.time+'</div>'
      +'</div></div>';
  }
  for(var i=0;i<a.items.length;i++){
    var item=a.items[i];
    html+='<div class="alert-item '+item.type+'">'
      +'<div class="alert-dot"></div><div>'
      +'<div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:2px">'+item.title+'</div>'
      +'<div style="font-size:11px;color:var(--text2)">'+item.desc+'</div>'
      +'<div style="font-size:10px;color:var(--text4);font-family:monospace;margin-top:2px">'+item.time+'</div>'
      +'</div></div>';
  }
  el.innerHTML=html;
}

