let currentScenario='quake',currentWarSub='overflow';

function setScenario(id){
  // еҶҚй»һдёҖж¬ЎеҗҢдёҖеҖӢ = еҸ–ж¶ҲйҒёеҸ–жё…з©ә
  if(currentScenario===id){
    currentScenario=null;
    document.querySelectorAll('.sim-btn').forEach(b=>b.classList.remove('sel'));
    document.getElementById('war-subs').style.display='none';
    var lbl=document.getElementById('sim-active-lbl');
    if(lbl) lbl.textContent='з•¶еүҚпјҡжңӘйҒёе®ҡ';
    var ds=document.getElementById('dash-sub');
    if(ds) ds.textContent='еҚіжҷӮзҒҪжғ…зёҪиҰҪ';
    return;
  }
  currentScenario=id;
  document.querySelectorAll('.sim-btn').forEach(b=>{
    const cls=[...b.classList].find(c=>['wind','flood','fire','quake','war-s','landslide','compound','drought','epidemic','tsunami'].includes(c));
    const match=(id==='war_s'&&cls==='war-s')||(cls===id);
    b.classList.toggle('sel',!!match);
  });
  document.getElementById('war-subs').style.display=id==='war_s'?'block':'none';
  const sc=SCENARIOS[id];
  if(!sc) return;
  document.getElementById('sim-active-lbl').textContent='з•¶еүҚпјҡ'+sc.name;
  document.getElementById('dash-sub').textContent='еҚіжҷӮзҒҪжғ… В· '+sc.sub;
  if(id==='war_s'){applyWarSub(currentWarSub);return;}
  applyScenarioStats(sc.stats);
  renderBugs(sc.bugs);
}
function setWarSub(sub,el){
  currentWarSub=sub;
  document.querySelectorAll('.war-sub').forEach(b=>b.classList.remove('sel'));
  if(el) el.classList.add('sel');
  applyWarSub(sub);
}
function applyWarSub(sub){ const ws=WAR_SUBS[sub]; if(!ws) return; applyScenarioStats(ws.stats); renderBugs([{type:ws.type,badge:'зҸҫе ҙжғ…еўғжҢ‘жҲ°',tag:ws.tag,title:ws.title,desc:ws.desc,solLabel:'зі»зөұйҳІзҰҰе•ҹеӢ•',sol:ws.sol,mods:ws.mods}]); }
function applyScenarioStats(stats){
  for(var i=0;i<stats.length;i++){
    var sv=stats[i];
    DATA.stats[i].lbl = sv.lbl || DATA.stats[i].lbl;
    DATA.stats[i].val = sv.val || DATA.stats[i].val;
    DATA.stats[i].sub = sv.sub || DATA.stats[i].sub;
    DATA.stats[i].color = sv.color || DATA.stats[i].color;
  }
  renderStats();
}
const TB={red:'var(--red-bg)',amber:'var(--amber-bg)',blue:'var(--blue-bg)'};
const TD={red:'var(--red-border)',amber:'var(--amber-border)',blue:'var(--blue-border)'};
const TC={red:'var(--red)',amber:'var(--amber)',blue:'var(--blue)'};
function renderBugs(bugs){
  var panel=document.getElementById('bug-panel');
  if(!panel) return;
  if(!bugs||!bugs.length){panel.className='bug-panel';panel.innerHTML='';return;}
  panel.className='bug-panel show';
  var html='';
  for(var bi=0;bi<bugs.length;bi++){
    var b=bugs[bi];
    var tbg=TB[b.type]||'var(--bg3)';
    var tbd=TD[b.type]||'var(--border)';
    var tco=TC[b.type]||'var(--text)';
    var mods='';
    var mm=b.mods||[];
    for(var mi=0;mi<mm.length;mi++){
      mods+='<div style="display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid var(--green-border);font-size:11px">'
        +'<span style="color:var(--green);font-weight:700">&#10003;</span>'
        +'<span style="flex:1;color:var(--text);font-weight:500">'+mm[mi]+'</span>'
        +'<span style="font-size:9px;font-family:monospace;color:var(--green);font-weight:700;background:white;padding:1px 5px;border-radius:4px;border:1px solid var(--green-border)">ACTIVE</span>'
        +'</div>';
    }
    html+='<div class="bug-card" style="border-color:'+tbd+'">'
      +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">'
      +'<span class="bug-badge" style="background:'+tbg+';color:'+tco+';border:1px solid '+tbd+'">'+b.badge+'</span>'
      +'<span style="font-size:9px;font-family:monospace;padding:2px 7px;border-radius:6px;background:var(--bg3);color:var(--text3);font-weight:600;border:1px solid var(--border)">[ '+b.tag+' ]</span>'
      +'</div>'
      +'<div style="font-size:13px;font-weight:700;color:'+tco+';margin-bottom:6px">'+b.title+'</div>'
      +'<div class="bug-desc">'+b.desc+'</div>'
      +'<div class="bug-solution">'
      +'<div class="bug-sol-lbl">&#9889; '+(b.solLabel||'зі»зөұйҳІзҰҰе•ҹеӢ•')+'</div>'
      +'<div class="bug-sol-text">'+b.sol+'</div>'
      +'<div class="bug-sol-modules">'+(b.mods||[]).map(function(m){return '<span class="sol-mod">'+m+'</span>';}).join('')+'</div>'
      +'</div>'
      +'</div>'
      +'<div class="bug-card" style="border-color:var(--green-border);background:var(--green-bg)">'
      +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">'
      +'<span class="bug-badge" style="background:var(--green-bg);color:var(--green);border:1px solid var(--green-border)">&#31995;&#32113;&#22238;&#24212;</span>'
      +'<span style="font-size:9px;font-family:monospace;padding:2px 7px;border-radius:6px;background:white;color:var(--green);border:1px solid var(--green-border);font-weight:700">&#9679; ACTIVE</span>'
      +'</div>'
      +'<div style="font-size:13px;font-weight:700;color:var(--green);margin-bottom:6px">&#25976;&#20301;&#36009;&#31310;&#27231;&#21046;&#19978;&#32218;</div>'
      +'<div class="bug-desc">&#20767;&#27979;&#21040;&#12300;'+b.tag+'&#12301;&#65292;&#20197;&#19979;&#27169;&#32068;&#24050;&#33258;&#21160;&#21854;&#21205;&#65306;</div>'
      +'<div style="margin-top:8px">'+mods+'</div>'
      +'</div>';
  }
  panel.innerHTML=html;
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
//  NAV / ROLE / STATE
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// в•җв•җв•җв•җв•җв•җв•җв•җ еҚіжҷӮеҗҢжӯҘдёӯеҸ°еұӨпјҲRTDBпјүв•җв•җв•җв•җв•җв•җв•җв•җ
var RTDB=(function(){
  var KEY='drms_rtdb';
  var listeners={};
  var bc=(typeof BroadcastChannel!=='undefined')?new BroadcastChannel('drms_rtdb_sync'):null;
  function readAll(){ try{ var raw=localStorage.getItem(KEY); return raw?JSON.parse(raw):{}; }catch(e){ return {}; } }
  function writeAll(db){ try{ localStorage.setItem(KEY,JSON.stringify(db)); }catch(e){} if(bc) bc.postMessage({t:Date.now()}); }
  function getPath(db,path){ if(!path) return db; var parts=path.split('/'); var cur=db; for(var i=0;i<parts.length;i++){ if(cur==null) return null; cur=cur[parts[i]]; } return (cur===undefined)?null:cur; }
  function setPath(db,path,val){ var parts=path.split('/'); var cur=db; for(var i=0;i<parts.length-1;i++){ if(cur[parts[i]]==null) cur[parts[i]]={}; cur=cur[parts[i]]; } if(val===null) delete cur[parts[parts.length-1]]; else cur[parts[parts.length-1]]=val; return db; }
  function notifyAll(){ Object.keys(listeners).forEach(function(lp){ var db=readAll(); listeners[lp].forEach(function(cb){ try{ cb(getPath(db,lp)); }catch(e){} }); }); }
  if(bc){ bc.onmessage=function(){ notifyAll(); }; }
  return {
    ref:function(path){ path=path||'';
      return {
        on:function(cb){ if(!listeners[path]) listeners[path]=[]; listeners[path].push(cb); cb(getPath(readAll(),path)); return cb; },
        off:function(cb){ if(listeners[path]) listeners[path]=listeners[path].filter(function(f){return f!==cb;}); },
        once:function(cb){ cb(getPath(readAll(),path)); },
        set:function(val){ var db=readAll(); setPath(db,path,val); writeAll(db); notifyAll(); },
        update:function(obj){ var db=readAll(); var cur=getPath(db,path)||{}; for(var k in obj){ cur[k]=obj[k]; } setPath(db,path,cur); writeAll(db); notifyAll(); },
        push:function(val){ var db=readAll(); var id='K'+Date.now().toString(36)+Math.floor(Math.random()*1000); setPath(db,path+'/'+id,val); writeAll(db); notifyAll(); return id; },
        remove:function(){ var db=readAll(); setPath(db,path,null); writeAll(db); notifyAll(); }
      };
    },
    seed:function(data){ var db=readAll(); var empty=true; for(var k in db){empty=false;break;} if(empty){ writeAll(data); } },
    reset:function(data){ writeAll(data); notifyAll(); }
  };
})();
