function setS(s){
  if(role==='sysadmin'&&s==='war'){
    toast('вҡ  и«ӢеҲҮжҸӣиҮізёҪжҺ§и§’иүІ','error');
    return;
  }
  if(role!=='admin'&&role!=='it'){
    toast('вҡ  ж¬ҠйҷҗдёҚи¶іпјҢеҸӘжңүзёҪжҺ§жҲ– IT еҝ—е·ҘеҸҜеҲҮжҸӣжҮүи®ҠзӢҖж…Ӣ');
    return;
  }
  state=s;
  sessionStorage.setItem('drms_state', state);
  document.getElementById('btn-p').className='sbtn'+(s==='peace'?' sp':'');
  document.getElementById('btn-w').className='sbtn'+(s==='war'?' sw':'');
  updateFooter();
  if(s==='war'){
    document.body.classList.add('wt-mode');
    document.getElementById('wt-overlay').classList.add('show');
    // иӢҘе№іжҷӮйқўжқҝе·ІйҒёе®ҡзҒҪйӣЈпјҢзӣҙжҺҘеё¶е…ҘдёҰи·іеҲ°гҖҢйҒёзӯүзҙҡгҖҚпјҢзңҒдёҖеҖӢеӢ•дҪң
    if(currentScenario&&WAR_MODULE_DEFAULTS[currentScenario]){
      wtPickScenario(currentScenario);
    }
    logSys('info','жҲ°жҷӮжЁЎејҸе•ҹеӢ•гҖӮе№іжҷӮ master иіҮж–ҷе·ІиҪүе”Ҝи®ҖйҺ–е®ҡгҖӮLINE OA еҜҶй‘°еҲҮжҸӣзӮәз·ҠжҖҘе°Ҳз”Ёй »йҒ“гҖӮ');
    logSys('ok','IT еҝ—е·Ҙе·Іж”¶еҲ°жҲ°жҷӮйҖҡе ұпјҢеҫҢеҸ°з¶ӯйҒӢйқўжқҝиҮӘеӢ•й–Ӣе•ҹгҖӮ');
    syncActive=true;changeRefreshRate(10000);updateSyncBtn();
    window.onbeforeunload=function(){ return 'жӮЁжңүжңӘе„Іеӯҳзҡ„ж“ҚдҪңпјҢзўәе®ҡйӣўй–Ӣпјҹ'; };
  } else {
    document.body.classList.remove('wt-mode');
    endSession();
    restoreAllModulesForPeace();
    logSys('info','е·ІеҲҮжҸӣеӣһе№іжҷӮжЁЎејҸгҖӮжүҖжңүжҲ°жҷӮиҰҶи“Ӣе·Іжё…йҷӨгҖӮ');
    changeRefreshRate(30000);if(syncActive){startSyncTimer();}updateSyncBtn();
    window.onbeforeunload=null;
  }
  showPage(activePage);
}
