  const badge=document.getElementById('gs-'+inp.dataset.id);
  if(badge){badge.className=inp.value?'gs-ok':'gs-empty';badge.textContent=inp.value?'е·ІиЁӯе®ҡ':'жңӘиЁӯе®ҡ';}
