  h+='<div><div class="iep-lbl">жҙ»еӢ•д»ЈиҷҹпјҲз¶ІеқҖз”ЁпјҢиӢұж•ёпјү</div><input class="inp" id="dsg-eid" value="'+esc(d.eventId)+'" oninput="dsgSet(\'eventId\',this.value)"></div>';
