  for(var i=0;i<d.questions.length;i++){ h+=dsgQRow(d.questions[i],i); }
  if(!d.questions.length) h+='<div style="font-size:12px;color:var(--text4);text-align:center;padding:14px 0">е°ҡз„ЎйЎҢзӣ®пјҢй»һгҖҢж–°еўһйЎҢзӣ®гҖҚй–Ӣе§Ӣ</div>';
  h+='</div>';
  // зҷјдҪҲеҚҖ
  h+='<div class="card"><div class="card-title">зҷјдҪҲ</div>';
  h+='<div style="font-size:11px;color:var(--text4);margin-bottom:10px">зҷјдҪҲжңғжҠҠйЎҢзӣ®еҜ«еӣһ Google Sheet зҡ„ Form_ConfigпјҢе ұеҗҚй Ғз«ӢеҚіз”ҹж•ҲпјҢдёҰз”ўз”ҹз¶ІеқҖ + QRгҖӮ</div>';
  h+='<div style="display:flex;gap:8px;flex-wrap:wrap">';
  h+='<button class="btn btn-blue" onclick="dsgPreview()">рҹ‘Ғ жӣҙж–°й җиҰҪ</button>';
  h+='<button class="btn btn-green" onclick="publishForm()">рҹ“Ө зҷјдҪҲиЎЁе–®</button>';
  h+='</div>';
  h+='<div id="dsg-publish-result" style="margin-top:12px"></div>';
  h+='</div>';
  h+='</div></div>';
