function addSignup(){
  var name=sanitizeInput((document.getElementById('su-name').value||'').trim());
  if(!name){ toast('вҡ  и«Ӣијёе…Ҙе§“еҗҚ'); return; }
  var group=document.getElementById('su-group').value;
  var phone=(document.getElementById('su-phone').value||'вҖ”').trim();
  var time=new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
  DATA.registry.signups[SIGNUP_DAY].push({name:name,group:group,phone:phone,time:time});
  logSys('ok','гҖҗе ұеҗҚгҖ‘'+(SIGNUP_DAY==='today'?'д»Ҡж—Ҙ':'жҳҺж—Ҙ')+'ж–°еўһ '+name+'пјҲ'+group+'пјү');
  toast('вң… '+name+' е·ІеҠ е…Ҙ'+(SIGNUP_DAY==='today'?'д»Ҡж—Ҙ':'жҳҺж—Ҙ')+'е ұеҗҚ');
  document.getElementById('su-name').value=''; document.getElementById('su-phone').value='';
  renderRegFlow();
}
function removeSignup(day,i){
  var r=DATA.registry.signups[day][i];
  DATA.registry.signups[day].splice(i,1);
  if(r) logSys('info','гҖҗе ұеҗҚгҖ‘з§»йҷӨ '+r.name);
  renderRegFlow();
}
