  if(v.checkin){toast('вҡ  '+v.name+' е·Із¶“е ұеҲ°йҒҺдәҶпјҒ');logSys('warn','GAS doGetпјҡ'+v.name+' йҮҚиӨҮжҺғзўј вҶ’ йҳ»ж“Ӣ');return;}
