var SAFETY={sent:0,safe:0,sos:0,roster:['жһ—её«е§җ','йҷіеё«е…„','ејөеё«е§җ','зҺӢеё«е…„','жқҺеё«е…„','еҗіеё«е§җ','е‘Ёеё«е…„','й„ӯеё«е§җ'],unreported:[]};
function fireRollCall(){
  SAFETY.sent=142; SAFETY.safe=0; SAFETY.sos=0;
  SAFETY.unreported=SAFETY.roster.slice();
  renderSafetyFunnel();
  logSys('warn','гҖҗй»һеҗҚгҖ‘е®үе…Ёеӣһе ұй»һеҗҚе·Іе»Јж’ӯиҮі 142 дҪҚеҝ—е·Ҙ Line');
  toast('рҹ“Ў й»һеҗҚе»Јж’ӯе·ІзҷјйҖҒпјҢзӯүеҫ…еӣһе ұ...');
  var step=0;
  var sim=setInterval(function(){
    step++;
    if(step<=6&&SAFETY.unreported.length){
      var who=SAFETY.unreported.shift();
      if(step===4){SAFETY.sos++;logSys('err','рҹҶҳ '+who+' еӣһе ұжұӮж•‘пјҒGPS е·Ійҷ„её¶пјҢж•‘жҸҙиҚүзЁҝе»әз«Ӣ');}
      else{SAFETY.safe++;logSys('ok',who+' еӣһе ұе®үе…Ё');}
      SAFETY.safe+=Math.floor(Math.random()*18+8);
      renderSafetyFunnel();
    } else {
      clearInterval(sim);
      var remain=Math.max(SAFETY.sent-SAFETY.safe-SAFETY.sos,0);
      if(remain>0){
        var tid='T'+String(Date.now()).slice(-3);
        DATA.tasks.items.unshift({id:tid,type:'survey',icon:'рҹ“һ',title:'е®үе…ЁиҝҪи№Ө вҖ” '+remain+' дҪҚеҝ—е·ҘжңӘеӣһе ұй»һеҗҚ',
          assign:'иЎҢж”ҝзө„',status:'pending',pct:0,
          created:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'}),
          received:'',endTime:new Date(Date.now()+3600000).toTimeString().substring(0,5),lineNotified:false,
          desc:'й»һеҗҚжңӘеӣһе ұпјҡ'+SAFETY.unreported.join('гҖҒ')+(remain>SAFETY.unreported.length?' зӯүе…ұ '+remain+' дҪҚ':'')+'пјҢи«Ӣйӣ»и©ұйҖҗдёҖзўәиӘҚ'});
        renderTasks();
        logSys('warn','й»һеҗҚж”¶ж–Ӯпјҡ'+remain+' дҪҚжңӘеӣһе ұ вҶ’ е·ІиҮӘеӢ•е»әз«ӢиҝҪи№Өд»»еӢҷ '+tid);
        toast('рҹ“һ иҝҪи№Өд»»еӢҷ '+tid+' е·Іе»әз«ӢпјҲ'+remain+' дҪҚжңӘеӣһе ұпјү');
      } else {
        logSys('ok','й»һеҗҚж”¶ж–Ӯпјҡе…Ёж•ёеӣһе ұе®үе…Ё вң“');
      }
    }
  },1200);
}
function renderSafetyFunnel(){
  var el=document.getElementById('safety-funnel'); if(!el) return;
  var pending=Math.max(SAFETY.sent-SAFETY.safe-SAFETY.sos,0);
  var html=makeFunnelRow([
    {bg:'var(--bg3)',border:'var(--border)',val:SAFETY.sent,lbl:'е·ІжҺЁж’ӯ',color:''},
    {bg:'var(--green-bg)',border:'var(--green-border)',val:SAFETY.safe,lbl:'е·Іеӣһе®үе…Ё',color:'var(--green)'},
    {bg:'var(--red-bg)',border:'var(--red-border)',val:SAFETY.sos,lbl:'жұӮж•‘',color:'var(--red)'},
    {bg:'var(--amber-bg)',border:'var(--amber-border)',val:pending,lbl:'жңӘеӣһе ұ',color:'var(--amber)'},
  ]);
  if(SAFETY.sent>0){
    var un=SAFETY.unreported.slice(0,6).join('гҖҒ');
    html+='<div style="font-size:10px;color:var(--text3)">'+(SAFETY.unreported.length?('еҗҚе–®иҝҪи№Өпјҡ'+un+(SAFETY.unreported.length>6?'вҖҰ':'')+' жңӘеӣһе ұ'):'вң“ иҝҪи№ӨеҗҚе–®е…Ёж•ёеӣһе ұ')+'</div>';
  }
  el.innerHTML=html;
}
function fireAlert(){
  const t=document.getElementById('al-title').value||'з·ҠжҖҘиӯҰе ұ';
  const a=document.getElementById('al-area').value||'е…ЁеҚҖеҹҹ';
  const m=document.getElementById('al-msg').value||'и«ӢжіЁж„Ҹе®үе…Ё';
  showModal('рҹҡЁ з·ҠжҖҘиӯҰе ұе·Іеј·еҲ¶жҺЁж’ӯ','е·ІзҷјйҖҒиҮі <strong style="color:var(--green)">142 дҪҚзҸҫе ҙеҝ—е·Ҙ</strong> зҡ„ Line OA','жЁҷйЎҢпјҡ'+t+'\nеҚҖеҹҹпјҡ'+a+'\nе…§е®№пјҡ'+m+'\nжҷӮй–“пјҡ'+new Date().toLocaleTimeString('zh-TW'));
  fireRollCall();
  if(typeof loaOASayAll==='function') loaOASayAll('рҹҡЁ з·ҠжҖҘиӯҰе ұ\n'+t+'\nеҚҖеҹҹпјҡ'+a+'\n'+m+'\nи«Ӣз«ӢеҚіеӣһе ұе®үе…ЁзӢҖж…ӢгҖӮ',{flex:'rollcall'});
}

// в”Җв”Җ TABS в”Җв”Җ
function switchTab(tid){
  document.querySelectorAll('#admin-gate .tab').forEach(function(t){
    var oc=t.getAttribute('onclick')||'';
    t.classList.toggle('act-tab',oc.indexOf("'"+tid+"'")>=0);
  });
  document.querySelectorAll('#admin-gate .tab-panel').forEach(p=>p.classList.remove('act-tp'));
  const el=document.getElementById(tid);
  if(el) el.classList.add('act-tp');
  if(tid==='t-todo') renderTodoList();
  if(tid==='t-sys') renderVersionPanel();
  if(tid==='t-perm') renderPermMatrix();
  if(tid==='t-mod'){ renderModuleManager(); renderAPIRows(); }
}
// в”Җв”Җ й–Ӣзҷјеҫ…иҫҰжё…е–®пјҲlocalStorage жҢҒд№…еҢ–пјүв”Җв”Җ
var TODO_DEFAULTS=[
  {pri:'P1',title:'еҝ—е·Ҙе ұеҗҚеҖӢиіҮеӯҳеҹәйҮ‘жңғжӘ”жЎҲзі»зөұ',
   bg:'зӣ®еүҚе ұеҗҚеҖӢиіҮпјҲиә«еҲҶиӯүгҖҒйӣ»и©ұгҖҒз·ҠжҖҘиҒҜзөЎдәәпјүеӯҳеңЁеүҚз«Ҝ localStorage иҲҮ Google SheetsпјҢжңӘеҠ еҜҶгҖҒз„ЎеҲҶзҙҡеӯҳеҸ–гҖӮ',
   why:'еҖӢиіҮеӨ–жҙ©йўЁйҡӘй«ҳпјӣдҫқеҖӢиіҮжі•й Ҳйҷҗе®ҡзү№е®ҡж¬ҠйҷҗдәәжүҚиғҪе®Ңе…Ёи®ҖеҸ–пјҢдёҖиҲ¬е№№йғЁеҸӘжҮүзңӢеҲ°йҒ®и”ҪеҫҢиіҮж–ҷгҖӮ',
   how:'еҫҢз«Ҝж¬ҠйҷҗеӯҳеҸ–еұӨпјҲGAS жҲ–еҹәйҮ‘жңғдјәжңҚеҷЁпјү+ ж¬„дҪҚзҙҡеҠ еҜҶпјӣеүҚз«Ҝдҫқи§’иүІ P0~P4 еӢ•ж…ӢйҒ®и”ҪпјӣеӯҳеҸ–з•ҷзЁҪж ёи»Ңи·ЎгҖӮ',
   done:false},
  {pri:'P1',title:'зҙ…йҡҠжј”з·ҙпјҡзӣӨй»һе„ҖиЎЁжқҝиіҮе®үжјҸжҙһ',
   bg:'ж•ҙеҖӢ DRMS зӮәе–®жӘ”еүҚз«ҜпјҢжүҖжңүйӮҸијҜиҲҮиіҮж–ҷеңЁзҖҸиҰҪеҷЁз«ҜпјҢз„ЎеҫҢз«Ҝй©—иӯүгҖӮ',
   why:'д»»дҪ•дәәеҸҜж”№еүҚз«Ҝз№һйҒҺж¬ҠйҷҗгҖҒеҒҪйҖ е ұеҲ°/жҙҫе·Ҙ/зөҗжЎҲпјӣеҖӢиіҮиҲҮжҢҮжҸ®йҸҲеҸҜиў«з«„ж”№гҖӮ',
   how:'зҙ…йҡҠжё¬и©Ұжё…е–®пјҡж¬Ҡйҷҗз№һйҒҺгҖҒXSSгҖҒlocalStorage з«„ж”№гҖҒGAS з«Ҝй»һжңӘжҺҲж¬ҠеӯҳеҸ–гҖҒQR еҒҪйҖ пјӣиЈңеҫҢз«Ҝй©—иӯүгҖӮ',
   done:false},
  {pri:'P2',title:'еӨҡдәәеҚ”дҪңе…ұз·Ё + жһ¶иЁӯеҹәйҮ‘жңғдјәжңҚеҷЁ',
   bg:'зӣ®еүҚз„ЎеӨҡдәәеҗҢжҷӮз·ЁијҜж©ҹеҲ¶пјҢBroadcastChannel еғ…еҗҢзҖҸиҰҪеҷЁеҲҶй ҒеҗҢжӯҘгҖӮ',
   why:'еҜҰйҡӣж•‘зҒҪйңҖеӨҡз«ҷй»һгҖҒеӨҡе№№йғЁеҗҢжҷӮж“ҚдҪңпјӣе–®ж©ҹзүҲз„Ўжі•и·ЁиЈқзҪ®еҚ”дҪңгҖӮ',
   how:'жһ¶иЁӯеҹәйҮ‘жңғдјәжңҚеҷЁпјӣеҫҢз«Ҝж”№ Firebase / WebSocket еҚіжҷӮеҗҢжӯҘпјҲзЁӢејҸе·Ій җз•ҷ RTDB д»ӢйқўеҸҜз„Ўз—ӣеҲҮжҸӣпјүпјӣеҠ дҪҝз”ЁиҖ…еёіиҷҹиҲҮдёҰзҷјйҺ–гҖӮ',
   done:false},
];
function loadTodos(){
  try{ var raw=localStorage.getItem('drms_todos'); if(raw) return JSON.parse(raw); }catch(e){}
  return JSON.parse(JSON.stringify(TODO_DEFAULTS));
}
function saveTodos(list){ try{ localStorage.setItem('drms_todos',JSON.stringify(list)); }catch(e){} }
var TODOS=loadTodos();
function renderTodoList(){
  var el=document.getElementById('todo-list'); if(!el) return;
  if(!TODOS.length){ el.innerHTML='<div style="font-size:12px;color:var(--text4);text-align:center;padding:20px 0">зӣ®еүҚз„Ўеҫ…иҫҰй …зӣ®</div>'; return; }
  var pColor={P1:'red',P2:'amber',P3:'blue'};
  var html='';
  for(var i=0;i<TODOS.length;i++){
    var t=TODOS[i];
    var dim=t.done?'opacity:.5':'';
    html+='<div style="border:1px solid var(--border);border-radius:var(--r-sm);padding:14px 16px;margin-bottom:10px;background:var(--bg2);'+dim+'">';
    html+='<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">';
    html+='<span class="badge badge-'+(pColor[t.pri]||'blue')+'">'+t.pri+'</span>';
    html+='<span style="font-size:13px;font-weight:700;flex:1;'+(t.done?'text-decoration:line-through':'')+'">'+esc(t.title)+'</span>';
    html+='<button class="btn btn-ghost btn-xs" onclick="toggleTodo('+i+')">'+(t.done?'вҶә йҮҚй–Ӣ':'вң“ е®ҢжҲҗ')+'</button>';
    html+='<button class="btn btn-ghost btn-xs" onclick="editTodo('+i+')">вңҺ</button>';
    html+='<button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="delTodo('+i+')">вң•</button>';
    html+='</div>';
    html+='<div style="font-size:11px;line-height:1.8;color:var(--text2)">';
    html+='<div style="margin-bottom:3px"><b style="color:var(--text3)">иғҢжҷҜпјҡ</b>'+esc(t.bg)+'</div>';
    html+='<div style="margin-bottom:3px"><b style="color:var(--text3)">зӮәдҪ•йҮҚиҰҒпјҡ</b>'+esc(t.why)+'</div>';
    html+='<div><b style="color:var(--text3)">жҠҖиЎ“ж–№еҗ‘пјҡ</b>'+esc(t.how)+'</div>';
    html+='</div></div>';
  }
  el.innerHTML=html;
}
function toggleTodo(i){ TODOS[i].done=!TODOS[i].done; saveTodos(TODOS); renderTodoList(); }
function delTodo(i){ if(!confirm('еҲӘйҷӨгҖҢ'+TODOS[i].title+'гҖҚпјҹ')) return; TODOS.splice(i,1); saveTodos(TODOS); renderTodoList(); toast('рҹ—‘ е·ІеҲӘйҷӨ'); }
function addTodo(){
  var title=prompt('еҫ…иҫҰжЁҷйЎҢпјҡ'); if(!title||!title.trim()) return;
  var pri=prompt('е„Әе…ҲзҙҡпјҲP1/P2/P3пјүпјҡ','P2')||'P2';
  TODOS.unshift({pri:pri.trim().toUpperCase(),title:title.trim(),bg:'(еҫ…иЈң)',why:'(еҫ…иЈң)',how:'(еҫ…иЈң)',done:false});
  saveTodos(TODOS); renderTodoList(); toast('пјӢ е·Іж–°еўһ');
}
function editTodo(i){
  var t=TODOS[i];
  var title=prompt('жЁҷйЎҢпјҡ',t.title); if(title===null) return;
  var bg=prompt('иғҢжҷҜпјҡ',t.bg); if(bg===null) return;
  var why=prompt('зӮәдҪ•йҮҚиҰҒпјҡ',t.why); if(why===null) return;
  var how=prompt('жҠҖиЎ“ж–№еҗ‘пјҡ',t.how); if(how===null) return;
  t.title=title.trim()||t.title; t.bg=bg; t.why=why; t.how=how;
  saveTodos(TODOS); renderTodoList(); toast('вңҺ е·Іжӣҙж–°');
}

// в”Җв”Җ MODAL/TOAST в”Җв”Җ
function showModal(title,body,detail){
  document.getElementById('modal-title').innerHTML=title;
  document.getElementById('modal-body').innerHTML=body;
  document.getElementById('modal-detail').textContent=detail||'';
  document.getElementById('modal').classList.add('show');
}
function closeModal(){document.getElementById('modal').classList.remove('show');}
let toastT;
function toast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg;el.style.display='block';
  clearTimeout(toastT);toastT=setTimeout(()=>el.style.display='none',3000);
}


