// Role definitions вҖ” stored here, editable via UI
let ROLES = [
  {id:'admin',     name:'зёҪжҺ§',   icon:'рҹҺ–', deletable:false},
  {id:'it',        name:'IT еҝ—е·Ҙ', icon:'рҹ”§', deletable:true},
  {id:'staff',     name:'иЎҢж”ҝзө„', icon:'рҹ“Ӣ', deletable:true},
  {id:'logistics', name:'зү©иіҮзө„', icon:'рҹ“Ұ', deletable:true},
];

// Permission matrix  { roleId: { moduleId: 'P0'|'P1'|'P2'|'P3'|'P4' } }
// peacetime: admin=P0 always, others default P1
// wartime: admin=P0 always, others default P1
function defaultPerms(moduleId, roleId, tab) {
  if (roleId === 'admin') return 'P0';
  if (roleId === 'it' && tab !== 'wartime') return 'P0';
  return 'P1';
}
let PERMS_PEACE = {};
let PERMS_WAR   = {};
function initPerms() {
  MODULES_PEACE.forEach(m => {
    ROLES.forEach(r => {
      if (!PERMS_PEACE[r.id]) PERMS_PEACE[r.id] = {};
      if (!PERMS_PEACE[r.id][m.id]) PERMS_PEACE[r.id][m.id] = defaultPerms(m.id, r.id, 'peacetime');
    });
  });
  MODULES_WAR.forEach(m => {
    ROLES.forEach(r => {
      if (!PERMS_WAR[r.id]) PERMS_WAR[r.id] = {};
      if (!PERMS_WAR[r.id][m.id]) PERMS_WAR[r.id][m.id] = defaultPerms(m.id, r.id, 'wartime');
    });
  });
}
initPerms();

// API endpoints
var API_ENDPOINTS = [
  {id:'api-1', name:'е…§ж”ҝйғЁиӯҰе ұ API', url:'https://alerts.ncdr.nat.gov.tw/api/v1/alerts', status:'ok',   enabled:true},
  {id:'api-2', name:'NCDR зҒҪжғ…иіҮиЁҠ',  url:'https://dmc.ncdr.nat.gov.tw/api/disaster',      status:'ok',   enabled:true},
  {id:'api-3', name:'Line Messaging', url:'https://api.line.me/v2/bot/message/broadcast',   status:'ok',   enabled:true},
  {id:'api-4', name:'ж°ЈиұЎзҪІйӣЁйҮҸ',     url:'https://opendata.cwa.gov.tw/api/v1/rain',        status:'err',  enabled:true},
  {id:'api-5', name:'Google Sheets',  url:'https://sheets.googleapis.com/v4/spreadsheets/', status:'warn', enabled:true},
];

let currentPTab = 'peacetime';
const P_CYCLE = ['P0','P1','P2','P3','P4'];
const P_LABELS = {
  P0: 'P0 е…Ёж¬Ҡ',
  P1: 'P1 з·ЁијҜ',
  P2: 'P2 дҝ®жӯЈ',
  P3: 'P3 й–ұи®Җ',
  P4: 'P4 з„Ўж¬Ҡ',
};

// в”Җв”Җ RENDER MATRIX в”Җв”Җ
function renderPermMatrix() {
  var mods  = currentPTab === 'peacetime' ? MODULES_PEACE : MODULES_WAR;
  var perms = currentPTab === 'peacetime' ? PERMS_PEACE   : PERMS_WAR;
  var el    = document.getElementById('perm-matrix');
  if (!el) return;
  var hdr = '<tr><th style="min-width:220px;text-align:left">жЁЎзө„</th>';
  for (var ri = 0; ri < ROLES.length; ri++) {
    var r = ROLES[ri];
    var chip = r.id === 'admin' ? 'admin-chip' : 'other-chip';
    var del  = r.deletable ? '<div class="role-del-btn" onclick="deleteRole(\'' + r.id + '\')" title="еҲӘйҷӨи§’иүІ">&times;</div>' : '';
    var nameSpan = r.id === 'admin'
      ? '<span>' + r.name + '</span>'
      : '<span onclick="renameRole(\'' + r.id + '\')" style="cursor:pointer" title="й»һж“Ҡз·ЁијҜеҗҚзЁұ">' + r.name + ' вңҸпёҸ</span>';
    hdr += '<th class="role-col"><div class="role-header-cell" style="position:relative;display:inline-block;margin:0 4px">'
         + '<div class="role-chip ' + chip + '">' + r.icon + ' ' + nameSpan + '</div>' + del
         + '</div></th>';
  }
  hdr += '</tr>';
  var body = '';
  for (var mi = 0; mi < mods.length; mi++) {
    var m = mods[mi];
    body += '<tr>';
    body += '<td><div class="mod-name">' + m.icon + ' ' + m.name + '</div><div class="mod-desc">' + m.desc + '</div></td>';
    for (var ri2 = 0; ri2 < ROLES.length; ri2++) {
      var ro = ROLES[ri2];
      var pval = (perms[ro.id] && perms[ro.id][m.id]) ? perms[ro.id][m.id] : defaultPerms(m.id, ro.id, currentPTab);
      var locked = ro.id === 'admin' || (ro.id === 'it' && currentPTab === 'peacetime');
      var oc = locked ? '' : 'onclick="cycleP(this)"';
      body += '<td class="perm-cell">'
            + '<div class="perm-badge ' + pval + (locked ? ' locked' : '') + '" '
            + 'data-role="' + ro.id + '" data-mod="' + m.id + '" data-tab="' + currentPTab + '" '
            + oc + ' title="' + P_LABELS[pval] + '">' + pval + '</div>'
            + '</td>';
    }
    body += '</tr>';
  }
  el.innerHTML = '<div style="overflow-x:auto"><table class="perm-tbl"><thead>' + hdr + '</thead><tbody>' + body + '</tbody></table></div>';
}

// в”Җв”Җ ROLE CRUD в”Җв”Җ
function addRole() {
  var name = prompt('и«Ӣијёе…Ҙж–°и§’иүІзө„еҲҘеҗҚзЁұпјҲдҫӢеҰӮпјҡйҶ«зҷӮзө„гҖҒи»ҠйҡҠзө„пјүпјҡ');
  if (!name || !name.trim()) return;
  var icon = prompt('и«Ӣијёе…Ҙи§’иүІ EmojiпјҲдҫӢеҰӮпјҡрҹҸҘгҖҒрҹҡӣпјүпјҡ') || 'рҹ‘Ө';
  var id = 'role_' + Date.now();
  ROLES.push({id:id, name:name.trim(), icon:icon, deletable:true});
  MODULES_PEACE.forEach(function(m){ if(!PERMS_PEACE[id]) PERMS_PEACE[id]={}; PERMS_PEACE[id][m.id]=defaultPerms(m.id,id,'peacetime'); });
  MODULES_WAR.forEach(function(m){   if(!PERMS_WAR[id])   PERMS_WAR[id]={};   PERMS_WAR[id][m.id]=defaultPerms(m.id,id,'wartime'); });
  var sel=document.getElementById('role-sel');
  if(sel){ var opt=document.createElement('option'); opt.value=id; opt.textContent=icon+' '+name.trim(); sel.appendChild(opt); }
  renderPermMatrix();
  toast('вң… ж–°и§’иүІгҖҢ'+name.trim()+'гҖҚе·Іе»әз«ӢпјҢй җиЁӯ P1');
}

function renameRole(id) {
  var r = ROLES.find(function(x){ return x.id===id; });
  if (!r) return;
  var newName = prompt('и«Ӣијёе…ҘгҖҢ'+r.name+'гҖҚзҡ„ж–°еҗҚзЁұпјҡ', r.name);
  if (!newName || !newName.trim() || newName.trim()===r.name) return;
  var oldName = r.name;
  r.name = newName.trim();
  var sel = document.getElementById('role-sel');
  if(sel){ [].forEach.call(sel.options, function(opt){ if(opt.value===id) opt.textContent=r.icon+' '+r.name; }); }
  renderPermMatrix();
  toast('вңҸпёҸ и§’иүІеҗҚзЁұе·Із”ұгҖҢ'+oldName+'гҖҚи®ҠжӣҙзӮәгҖҢ'+r.name+'гҖҚ');
}

function deleteRole(id) {
  var r = ROLES.find(function(x){ return x.id===id; });
  if (!r || !r.deletable) return;
  if (!confirm('зўәе®ҡиҰҒеҲӘйҷӨи§’иүІгҖҢ'+r.name+'гҖҚпјҹе°ҮеҗҢжӯҘз§»йҷӨжүҖжңүж¬ҠйҷҗиЁӯе®ҡгҖӮ')) return;
  ROLES = ROLES.filter(function(x){ return x.id!==id; });
  delete PERMS_PEACE[id]; delete PERMS_WAR[id];
  var sel = document.getElementById('role-sel');
  if(sel){ [].forEach.call(sel.options, function(opt){ if(opt.value===id) sel.remove(opt.index); }); }
  if(role===id) setRole('admin');
  renderPermMatrix();
  toast('рҹ—‘ и§’иүІзө„еҲҘе·Іе®үе…Ёз§»йҷӨ');
}
function switchPTab(tab){
  currentPTab=tab;
  document.querySelectorAll('.ptab').forEach(function(p){p.classList.remove('act-ptab');});
  var tabs=document.querySelectorAll('.ptab');
  if(tab==='peacetime'&&tabs[0]) tabs[0].classList.add('act-ptab');
  if(tab==='wartime'&&tabs[1]) tabs[1].classList.add('act-ptab');
  renderPermMatrix();
}
