// в”Җв”Җ зҸҫе ҙз«Ҝ в”Җв”Җ
function renderField(){
  var el=document.getElementById('w-field-content');
  if(!el) return;
  var f=DATA.field;

  // Stat row
  var statRow='<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px">';
  var stats=[
    {label:f.households.label, cur:f.households.cur, total:f.households.total, color:'red'},
    {label:f.victims.label,    cur:f.victims.cur,    total:f.victims.total,    color:'amber'},
    {label:f.volunteers.label, cur:f.volunteers.cur,  total:f.volunteers.target, color:'green'},
  ];
  for(var i=0;i<stats.length;i++){
    var st=stats[i];
    var pct=Math.round(st.cur/st.total*100);
    statRow+='<div class="stat-card '+st.color+'" style="padding:14px 16px">'
      +'<div class="accent-bar"></div>'
      +'<div class="stat-lbl">'+st.label+'</div>'
      +'<div class="stat-val">'+st.cur.toLocaleString()+'</div>'
      +'<div class="prog-bar" style="margin-top:8px"><div class="prog-fill" style="width:'+pct+'%;background:var(--'+st.color+')"></div></div>'
      +'<div class="stat-sub" style="margin-top:3px">/ '+st.total.toLocaleString()+' ('+pct+'%)</div>'
      +'</div>';
  }
  statRow+='</div>';

  // Shelters
  var shelterHtml='<div class="card" style="margin-bottom:14px">'
    +'<div class="card-title"><span class="dot" style="background:var(--blue)"></span>ж”¶е®№жүҖзҸҫжіҒ</div>'
    +'<div class="shelter-row">';
  for(var i=0;i<f.shelters.length;i++){
    var sh=f.shelters[i];
    var pct2=Math.round(sh.cur/sh.cap*100);
    var capColor=pct2>90?'red':pct2>70?'amber':'green';
    shelterHtml+='<div class="shelter-card">'
      +'<div class="shelter-name">'+sh.name+'</div>'
      +'<div class="shelter-cap" style="font-size:22px;font-weight:700;color:var(--'+capColor+');font-family:Inter">'+sh.cur+'<span style="font-size:12px;color:var(--text4);font-weight:400"> / '+sh.cap+'</span></div>'
      +'<div class="prog-bar" style="margin:6px 0"><div class="prog-fill" style="width:'+pct2+'%;background:var(--'+capColor+')"></div></div>'
      +'<div style="display:flex;gap:6px;margin-top:6px">'
      +'<span class="badge '+(sh.supplies==='е……и¶і'?'badge-green':'badge-red')+'">зү©иіҮ:'+sh.supplies+'</span>'
      +'<span class="badge '+(sh.medical==='и¶іеӨ '?'badge-green':'badge-red')+'">йҶ«иӯ·:'+sh.medical+'</span>'
      +'</div></div>';
  }
  shelterHtml+='</div></div>';

  // Supplies
  var supplyHtml='<div class="card">'
    +'<div class="card-title"><span class="dot" style="background:var(--amber)"></span>зү©иіҮзҸҫжіҒ</div>';
  for(var i=0;i<f.supplies.length;i++){
    var sp=f.supplies[i];
    var pct3=Math.round(sp.stock/sp.need*100);
    supplyHtml+='<div class="supply-row">'
      +'<div style="width:80px;font-size:12px;font-weight:600;color:var(--text)">'+sp.item+'</div>'
      +'<div style="flex:1;margin:0 12px"><div class="prog-bar" style="height:6px"><div class="prog-fill" style="width:'+Math.min(pct3,100)+'%;background:var(--'+sp.status+')"></div></div></div>'
      +'<div style="font-size:11px;font-family:monospace;color:var(--text3);width:100px;text-align:right">'+sp.stock+' / '+sp.need+' '+sp.unit+'</div>'
      +'<span class="badge '+(sp.status==='green'?'badge-green':sp.status==='amber'?'badge-amber':'badge-red')+'" style="width:36px;text-align:center">'+(pct3>=100?'и¶і':''+pct3+'%')+'</span>'
      +'</div>';
  }
  supplyHtml+='</div>';

  el.innerHTML=statRow+shelterHtml+supplyHtml;
}

