// в”Җв”Җ COUNTDOWN HELPERS в”Җв”Җ
function parseHHMM(str) {
  if(!str) return null;
  var parts = str.split(':');
  if(parts.length < 2) return null;
  var now = new Date();
  var d = new Date(now.getFullYear(), now.getMonth(), now.getDate(),
    parseInt(parts[0]), parseInt(parts[1]), 0, 0);
  return d;
}
function formatCountdown(endTimeStr) {
  var end = parseHHMM(endTimeStr);
  if(!end) return 'вҖ”';
  var now = new Date();
  var diff = end - now;
  if(diff <= 0) return '<span style="color:var(--red);font-weight:700">е·Іи¶…жҷӮ</span>';
  var h = Math.floor(diff/3600000);
  var m = Math.floor((diff%3600000)/60000);
  var s = Math.floor((diff%60000)/1000);
  var color = diff < 900000 ? 'var(--red)' : diff < 1800000 ? 'var(--amber)' : 'var(--green)';
  var txt = (h>0?h+'h ':'') + m + 'm ' + s + 's';
  return '<span style="color:'+color+';font-weight:700;font-family:monospace">'+txt+'</span>';
}
function formatReceivedDelay(created, received) {
  if(!received) return '<span style="color:var(--text4)">жңӘзўәиӘҚ</span>';
  var c = parseHHMM(created);
  var r = parseHHMM(received);
  if(!c||!r) return received;
  var diff = r - c;
  if(diff < 0) diff += 86400000;
  var m = Math.floor(diff/60000);
  var s = Math.floor((diff%60000)/1000);
  var delayColor = diff > 300000 ? 'var(--red)' : diff > 60000 ? 'var(--amber)' : 'var(--green)';
  return '<span style="color:'+delayColor+'">'+received+' <span style="font-size:9px">(+'+m+'m'+s+'s)</span></span>';
}
var countdownTimer = null;
var escalated = {};
function startCountdown() {
  if(countdownTimer) clearInterval(countdownTimer);
  countdownTimer = setInterval(function(){
    document.querySelectorAll('.task-countdown').forEach(function(el){
      var t = el.dataset.end;
      el.innerHTML = formatCountdown(t);
    });
    for(var i=0;i<DATA.tasks.items.length;i++){
      var tk=DATA.tasks.items[i];
      if(tk.status==='done'||escalated[tk.id]) continue;
      var end=parseHHMM(tk.endTime);
      if(end&&end-new Date()<=0){
        escalated[tk.id]=true;
        logSys('err','гҖҗи¶…жҷӮеҚҮзҙҡгҖ‘'+tk.id+' '+tk.title.substring(0,18)+'вҖҰ е·ІйҖҫжңҹпјҢиҮӘеӢ•жҺЁж’ӯжҸҗйҶ’зө„й•·дёҰйҖҡзҹҘзёҪжҺ§');
        toast('рҹ”ҙ '+tk.id+' е·Іи¶…жҷӮпјҢеҚҮзҙҡйҖҡзҹҘе·ІзҷјйҖҒ');
      }
    }
  }, 1000);
}


// в”Җв”Җ PERMISSION REQUEST SYSTEM в”Җв”Җ
var pendingPerm = null;
function requestPerm(roleName, modName, fromP, toP, reason){
  pendingPerm = {roleName:roleName, modName:modName, fromP:fromP, toP:toP};
  var banner = document.getElementById('perm-banner');
  var body   = document.getElementById('perm-banner-body');
  body.innerHTML = '<strong>'+roleName+'</strong> з”іи«Ӣе°ҮгҖҢ'+modName+'гҖҚж“ҚдҪңж¬Ҡйҷҗз”ұ '
    +'<strong>'+fromP+'</strong> жҸҗеҚҮиҮі <strong>'+toP+'</strong>гҖӮ'
    +(reason?'<br><span style="color:var(--amber)">рҹ’Ў '+reason+'</span>':'');
  banner.classList.add('show');
  logSys('warn','жҸҗж¬Ҡи«ӢжұӮпјҡ'+roleName+' з”іи«Ӣ '+modName+' '+fromP+' вҶ’ '+toP);
}
var TEMP_GRANTS=[];
function approvePerm(isApprove){
  document.getElementById('perm-banner').classList.remove('show');
  if(!pendingPerm) return;
  if(isApprove){
    var targetRole='staff';
    var targetMod='vol_hub';
    var prevP=(PERMS_PEACE[targetRole]&&PERMS_PEACE[targetRole][targetMod])||'P1';
    var newP=pendingPerm.toP.split(' ')[0];
    if(!PERMS_PEACE[targetRole]) PERMS_PEACE[targetRole]={};
    PERMS_PEACE[targetRole][targetMod]=newP;
    var key='ROUTE-KEY-'+Date.now().toString(36).slice(-6).toUpperCase();
    var grant={role:targetRole,mod:targetMod,prevP:prevP,key:key,expires:Date.now()+30000};
    TEMP_GRANTS.push(grant);
    renderPermMatrix();
    logSys('ok','гҖҗзёҪжҺ§ж ёеҮҶгҖ‘'+pendingPerm.roleName+' жҸҗж¬ҠиҮі '+newP+'пјҢзҹ©йҷЈе·ІеҚіжҷӮз”ҹж•ҲпјҲйҮ‘й‘° '+key+'пјҢ30 з§’еҫҢиҮӘеӢ•еӣһж”¶ вҖ” жј”з·ҙеҠ йҖҹпјү');
    toast('вң… жҸҗж¬Ҡе·Іж ёеҮҶдёҰеҜ«е…Ҙзҹ©йҷЈпјҢ30 з§’еҫҢиҮӘеӢ•еӣһж”¶');
    setTimeout(function(){
      var idx=TEMP_GRANTS.indexOf(grant);
      if(idx<0) return;
      TEMP_GRANTS.splice(idx,1);
      PERMS_PEACE[grant.role][grant.mod]=grant.prevP;
      renderPermMatrix();renderNav();
      logSys('warn','гҖҗиҮӘеӢ•еӣһж”¶гҖ‘иҮЁжҷӮйҮ‘й‘° '+grant.key+' е·ІеҲ°жңҹпјҢ'+grant.role+'В·'+grant.mod+' ж¬ҠйҷҗйӮ„еҺҹзӮә '+grant.prevP);
      toast('вҸі иҮЁжҷӮжҸҗж¬Ҡе·ІеҲ°жңҹиҮӘеӢ•еӣһж”¶');
    },30000);
  } else {
    logSys('info','гҖҗзёҪжҺ§жӢ’зө•гҖ‘'+pendingPerm.roleName+' жҸҗж¬Ҡз”іи«Ӣе·Ій§ҒеӣһгҖӮ');
    toast('вҡӘ жҸҗж¬Ҡз”іи«Ӣе·ІжӢ’зө•');
  }
  pendingPerm = null;
}

// в”Җв”Җ SYSLOG в”Җв”Җ
var logEntries = [];
function logSys(level, msg){
  var time = new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
  var colorMap = {ok:'slog-ok', warn:'slog-warn', err:'slog-err', info:'slog-info'};
  var prefix   = {ok:'вң“', warn:'вҡ ', err:'вң—', info:'в„№'};
  logEntries.unshift({time:time, level:level, msg:msg});
  if(logEntries.length > 50) logEntries.pop();
  if(typeof telemetryLog==='function') telemetryLog(level,msg);
  var el = document.getElementById('syslog');
  if(!el) return;
  el.innerHTML = logEntries.map(function(e){
    return '<div class="syslog-entry"><span class="slog-time">'+e.time+'</span>'
      +'<span class="'+colorMap[e.level]+'">'+prefix[e.level]+'</span> '+e.msg+'</div>';
  }).join('');
}
