function aiSearchFeature(q){
  var box=document.getElementById('ai-feature-results'); if(!box) return;
  q=(q||'').trim().toLowerCase();
  if(!q){ box.innerHTML=''; return; }
  var hits=[];
  for(var i=0;i<NAV_CFG.length;i++){
    var item=NAV_CFG[i];
    if(disabledModules.has(item.id)) continue;
    var lbl=item.label.toLowerCase();
    var grp=(item.group||'').toLowerCase();
    if(lbl.indexOf(q)>=0||grp.indexOf(q)>=0||item.id.indexOf(q)>=0){ hits.push(item); }
  }
  if(!hits.length){ box.innerHTML=''; return; }
  var v='<div style="font-size:10px;color:var(--text4);margin-bottom:5px">и·іиҮіеҠҹиғҪпјҲ'+hits.length+'пјү</div><div style="display:flex;flex-wrap:wrap;gap:6px">';
  for(var k=0;k<hits.length&&k<6;k++){
    var h=hits[k];
    v+='<button class="btn btn-ghost" style="font-size:11px;padding:6px 10px" onclick="gotoFeature(\''+h.id+'\')">'+h.icon+' '+h.label+'</button>';
  }
  v+='</div>';
  box.innerHTML=v;
}
function gotoFeature(id){
  var box=document.getElementById('ai-feature-results'); if(box) box.innerHTML='';
  var inp=document.getElementById('ai-challenge-input'); if(inp) inp.value='';
  if(window.innerWidth<=768) document.body.classList.remove('nav-open');
  showPage(id);
}
function runAIAnalysis(){
  var inputEl=document.getElementById('ai-challenge-input');
  var promptText=inputEl?inputEl.value.trim():'';
  if(!promptText){toast('вҡ  и«Ӣе…Ҳијёе…ҘзӘҒзҷјзҒҪжғ…жғ…еўғе…§е®№');return;}
  var match=null;
  for(var i=0;i<AI_RULES.length;i++){
    var r=AI_RULES[i];
    for(var j=0;j<r.keys.length;j++){
      if(promptText.includes(r.keys[j])){match=r;break;}
    }
    if(match) break;
  }
  if(!match){
    match={title:'еӢ•ж…ӢиӨҮеҗҲеһӢж–°еһӢж…ӢзҒҪжғ…',tag:'зӘҒзҷјжҮүи®Ҡ',type:'amber',
      sol:'е•ҹеӢ•е…ЁжЁЎзө„жҷәж…§йҳІзҰҰж©ҹеҲ¶пјҢйҮқе°Қеӣһе ұж•ёж“ҡеј·еҲ¶йҖІиЎҢдәӨеҸүй©—иӯүдёҰеӢ•ж…ӢзІҫз°Ўж ёеҝғд»»еӢҷзӣ®жЁҷ',
      mods:['йңҖжұӮеҪҷж•ҙ','жҢҮд»Өй©—иӯү','иҝҪи№ӨзңӢжқҝ']};
  }
  // Reuse renderBugs with AI-generated content
  renderBugs([{
    type:match.type,
    badge:'AI еҲҶжһҗзөҗжһң',
    tag:match.tag,
    title:match.title,
    desc:'гҖҢ'+promptText+'гҖҚ',
    solLabel:'зі»зөұйҳІзҰҰиҮӘеӢ•е»әиӯ°',
    sol:match.sol,
    mods:match.mods
  }]);
  logSys('ok','AI жҲ°иЎ“еҲҶжһҗе®ҢжҲҗпјҡеҒөжё¬еҲ°гҖҢ'+match.tag+'гҖҚпјҢе·ІиҮӘеӢ•е°ҚжҺҘ '+match.mods.length+' еҖӢйҳІзҰҰжЁЎзө„');
  if(match.tag==='зү©иіҮйҒҺйҮҸ'||match.tag==='дәәеҠӣдёҚи¶і'||promptText.includes('зү©иіҮ')||promptText.includes('зјә')){
    var rid='REQ-AI'+String(Date.now()).slice(-3);
    DATA.warehouse.reqs.unshift({id:rid,item:'рҹ“Ұ з¶ңеҗҲзү©иіҮ',qty:'Г—50',site:'AI еҲӨе®ҡзҒҪй»һ',due:'1 е°ҸжҷӮе…§',prio:'P1',status:'еҫ…жҙҫжЎҲ',driver:''});
    logSys('warn','AI иҮӘеӢ•з”ҹжҲҗйңҖжұӮе–® '+rid+'пјҲдҫқи®ҠеҢ–зҗғе…§е®№еҲӨе®ҡпјүпјҢе·ІйҖІе…ҘжҙҫжЎҲдҪҮеҲ—');
    renderNav();
    toast('рҹӨ– AI е·Із”ҹжҲҗйңҖжұӮе–® '+rid+' вҶ’ зү©иіҮеҖүе„ІжҙҫжЎҲеҸ°');
  } else {
    toast('рҹӨ– AI еҲҶжһҗе®ҢжҲҗпјҢе·ІиҮӘеӢ•е°ҚжҺҘйҳІзҰҰжЁЎзө„');
  }
}

// в”Җв”Җ WARTIME HOTFIX DISPATCHER в”Җв”Җ
function dispatchHotfix(){
  var desc=document.getElementById('hotfix-desc').value.trim();
  if(!desc){toast('вҡ  и«ӢеЎ«еҜ«дҝ®жӯЈзҙ°зҜҖиӘӘжҳҺ');return;}
  var mod=document.getElementById('hotfix-module').value;
  var payload=document.getElementById('hotfix-payload').value.trim();
  var targets=[];
  document.querySelectorAll('#hotfix-targets input[type=checkbox]:checked').forEach(function(cb){targets.push(cb.value);});
  if(!targets.length){toast('вҡ  и«ӢйҒёж“ҮиҮіе°‘дёҖеҖӢзӣ®жЁҷз«Ҝй»һ');return;}
  var chars='ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  var rand='';
  for(var i=0;i<12;i++) rand+=chars[Math.floor(Math.random()*chars.length)];
  var token='DRMS-PATCH-2026-'+rand;
  var delays=targets.map(function(t){return t+' +'+Math.floor(Math.random()*30+5)+'ms еҗҢжӯҘжҲҗеҠҹ';});
  var hashStr=payload?btoa(payload.substring(0,32)).substring(0,20)+'...':'(з„Ў Payload)';
  var NL='\n';
  var detail='еҗҢжӯҘйҮ‘й‘°пјҡ'+token+NL+'дҝ®жӯЈжЁЎзө„пјҡ'+mod+NL+'дҝ®жӯЈиӘӘжҳҺпјҡ'+desc+NL+NL+'з«Ҝй»һжҺҘж”¶еӣһе ұпјҡ'+NL+delays.join(NL)+NL+NL+'Payload Hashпјҡ'+hashStr;
  toast('рҹ“Ў з•°ең°зҶұдҝ®иЈңйҮ‘й‘°е·Іе»Јж’ӯжҙҫйҖҒпјҒ');
  logSys('ok','гҖҗи·Ёз«ҷеҗҢжӯҘгҖ‘жҲҗеҠҹеҗ‘ '+targets.join('гҖҒ')+' з«Ҝй»һжҙҫйҖҒдҝ®иЈңеҜҶй‘°гҖӮз•°ең°зүҲжң¬е·Іеј·еҲ¶еҗҢжӯҘиҮі v4.0.1-hotfix');
  showModal('рҹҡҖ йҒ з«ҜзҶұдҝ®иЈңйғЁзҪІжҲҗеҠҹ','е·ІйҖҸйҒҺеҠ еҜҶйҖҡйҒ“е°Үдҝ®жӯЈжЎҲжҙҫйҖҒиҮі <strong style="color:var(--green)">'+targets.length+' иҷ•</strong>з•°ең°з«ҷй»һпјҢеј·еҲ¶иҰҶи“Ӣжң¬ең° Master зҜҖй»һгҖӮ',detail);
}

