var VH_TAB='checkin';
function renderVolHub(){
  ['checkin','medical','roster','manage'].forEach(function(x){
    var b=document.getElementById('vhtab-'+x); if(b) b.className='btn '+(x===VH_TAB?'btn-blue':'btn-ghost');
    var p=document.getElementById('vh-'+x); if(p) p.style.display=(x===VH_TAB?'':'none');
  });
  if(VH_TAB==='checkin'){ renderRegistry(); renderRegFlow(); renderRegStats(); loadFormPreview(); }
  else if(VH_TAB==='medical'){ renderMedicalCheckin(); }
  else if(VH_TAB==='roster'){ renderSheetReg(); }
}
function setVolHubTab(t){ VH_TAB=t; renderVolHub(); }

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ ж°‘зңҫжұӮеҠ©йҖҡе ұпјҲзҒҪж°‘з«Ҝ + ж”¶д»¶еҢЈпјүв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
var RELIEF_TAB='inbox';
function setReliefTab(t){
  RELIEF_TAB=t;
  ['inbox','map','form'].forEach(function(x){var b=document.getElementById('rrtab-'+x);if(b)b.className='btn '+(x===t?'btn-blue':'btn-ghost');});
  var tid=document.getElementById('needs-relief-content')?'needs-relief-content':'relief-req-content';
  renderReliefReq(tid);
}
function renderReliefReq(targetId){
  var el=document.getElementById(targetId||'relief-req-content'); if(!el) return;
  if(RELIEF_TAB==='map') el.innerHTML=renderReliefMap();
  else if(RELIEF_TAB==='form') el.innerHTML=renderReliefForm();
  else el.innerHTML=renderReliefInbox();
}
function renderReliefInbox(){
  var d=DATA.relief_req;
  var pend=d.requests.filter(function(r){return r.status==='еҫ…иҷ•зҗҶ';}).length;
  var sent=d.requests.filter(function(r){return r.status==='е·ІиҪүжҙҫ'||r.status==='иҷ•зҗҶдёӯ';}).length;
  var dup=d.requests.filter(function(r){return r.dup&&r.status==='еҫ…иҷ•зҗҶ';}).length;
  var tColor={'жҗ¶ж•‘':'badge-red','йҶ«зҷӮ':'badge-purple','ж”¶е®№':'badge-blue','зү©иіҮ':'badge-amber'};
  var sColor={'еҫ…иҷ•зҗҶ':'badge-amber','е·ІиҪүжҙҫ':'badge-blue','иҷ•зҗҶдёӯ':'badge-purple','е·ІзөҗжЎҲ':'badge-green'};
  var html='<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:14px">'
    +'<div class="stat-card red" style="padding:14px;position:relative"><div class="accent-bar"></div><div class="stat-lbl">еҫ…иҷ•зҗҶжұӮеҠ©</div><div class="stat-val">'+pend+'</div><div class="stat-sub">д»¶</div></div>'
    +'<div class="stat-card blue" style="padding:14px;position:relative"><div class="accent-bar"></div><div class="stat-lbl">е·ІиҪүжҙҫ / иҷ•зҗҶдёӯ</div><div class="stat-val">'+sent+'</div><div class="stat-sub">д»¶</div></div>'
    +'<div class="stat-card amber" style="padding:14px;position:relative"><div class="accent-bar"></div><div class="stat-lbl">з–‘дјјйҮҚиӨҮ</div><div class="stat-val">'+dup+'</div><div class="stat-sub">д»¶еҫ…иҰҶж ё</div></div>'
    +'</div>';
  html+='<div class="card"><div class="card-title">рҹҶҳ '+d.title+'пјҲдҫқжҷӮй–“жҺ’еәҸпјү</div>'
    +'<table class="tbl"><thead><tr><th>е–®иҷҹ</th><th>жҷӮй–“</th><th>йЎһеһӢ</th><th>йҖҡе ұдәә</th><th>дҪҚзҪ®</th><th>дәәж•ё</th><th>жҸҸиҝ°</th><th>зӢҖж…Ӣ</th><th>ж“ҚдҪң</th></tr></thead><tbody>';
  for(var i=0;i<d.requests.length;i++){
    var r=d.requests[i];
    html+='<tr'+(r.dup&&r.status==='еҫ…иҷ•зҗҶ'?' style="background:var(--amber-bg)"':'')+'>'
      +'<td class="sh-time">'+r.id+'</td><td class="sh-time">'+r.time+'</td>'
      +'<td><span class="badge '+(tColor[r.type]||'badge-blue')+'">'+r.type+'</span></td>'
      +'<td>'+r.name+'<div style="font-size:9px;color:var(--text4);font-family:monospace">'+r.phone+'</div></td>'
      +'<td style="font-size:11px">'+r.location+'</td>'
      +'<td style="text-align:center;font-weight:600">'+r.people+'</td>'
      +'<td style="font-size:11px;max-width:210px">'+r.desc+'</td>'
      +'<td><span class="badge '+(sColor[r.status]||'badge-amber')+'">'+r.status+'</span></td><td>';
    if(r.status==='еҫ…иҷ•зҗҶ'){
      if(r.dup) html+='<button class="btn btn-ghost btn-xs" onclick="reliefMarkDup('+i+')">вң“ зўәиӘҚдҪөе–®</button>';
      else html+='<button class="btn btn-red btn-xs" onclick="reliefToDispatch('+i+')">вҡЎ иҪүиӘҝеәҰдёӯеҸ°</button>';
    } else if(r.status==='е·ІиҪүжҙҫ'||r.status==='иҷ•зҗҶдёӯ'){
      html+='<button class="btn btn-green btn-xs" onclick="reliefClose('+i+')">вң“ зөҗжЎҲ</button>';
    } else html+='<span style="font-size:9px;color:var(--text4)">вң“</span>';
    html+='</td></tr>';
  }
  html+='</tbody></table>'
    +'<div style="font-size:10px;color:var(--text4);margin-top:10px">рҹ’Ў гҖҢвҡЎ иҪүиӘҝеәҰдёӯеҸ°гҖҚиҮӘеӢ•ж–јеҚіжҷӮиӘҝеәҰдёӯеҸ°д»»еӢҷжұ е»әз«Ӣд»»еӢҷпјҲжҗ¶ж•‘/йҶ«зҷӮвҶ’P1гҖҒж”¶е®№вҶ’P2гҖҒзү©иіҮвҶ’P3пјүпјҢжү“йҖҡгҖҢж°‘зңҫжұӮеҠ©вҶ’жҢҮжҸ®жҙҫе·ҘгҖҚзҡ„ж–·й»һгҖӮ</div></div>';
  return html;
}
function reliefToDispatch(i){
  var r=DATA.relief_req.requests[i];
  var prio={'жҗ¶ж•‘':'P1','йҶ«зҷӮ':'P1','ж”¶е®№':'P2','зү©иіҮ':'P3'}[r.type]||'P2';
  var tm=new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
  try{ if(typeof RTDB!=='undefined'&&RTDB.ref){ RTDB.ref('tasks').push({title:'гҖҗж°‘зңҫжұӮеҠ© '+r.id+'гҖ‘'+r.type+'В·'+r.location+'пјҲ'+r.people+'дәәпјү',priority:prio,status:'еҫ…жҙҫе·Ҙ',assignee:'',lockedBy:'',created:tm}); } }catch(e){}
  r.status='е·ІиҪүжҙҫ'; r.taskRef='е·Іе»әд»»еӢҷ';
  logSys('warn','гҖҗж°‘зңҫжұӮеҠ©гҖ‘'+r.id+' е·ІиҪүеҚіжҷӮиӘҝеәҰдёӯеҸ°д»»еӢҷжұ пјҲ'+prio+'пјү'+r.location);
  toast('вҡЎ '+r.id+' е·ІиҪүиӘҝеәҰдёӯеҸ°пјҲ'+prio+'пјү');
  renderReliefReq(); saveData();
}
function reliefMarkDup(i){
  var r=DATA.relief_req.requests[i];
  r.status='е·ІзөҗжЎҲ'; r.desc='вң“ е·ІзўәиӘҚиҲҮж—ўжңүе–®йҮҚиӨҮпјҢдҪөе–®иҷ•зҗҶ';
  logSys('info','гҖҗж°‘зңҫжұӮеҠ©гҖ‘'+r.id+' зўәиӘҚйҮҚиӨҮдҪөе–®');
  toast('вң“ е·ІдҪөе–®пјҡ'+r.id); renderReliefReq(); saveData();
}
function reliefClose(i){
  var r=DATA.relief_req.requests[i]; r.status='е·ІзөҗжЎҲ';
  logSys('ok','гҖҗж°‘зңҫжұӮеҠ©гҖ‘'+r.id+' е·ІзөҗжЎҲ'); toast('вң“ '+r.id+' е·ІзөҗжЎҲ');
  renderReliefReq(); saveData();
}
function renderReliefMap(){
  var d=DATA.relief_req, byArea={};
  d.requests.forEach(function(r){
    if(r.status==='е·ІзөҗжЎҲ') return;
    var a=r.location.substring(0,3);
    if(!byArea[a]) byArea[a]={count:0,people:0,types:{}};
    byArea[a].count++; byArea[a].people+=r.people; byArea[a].types[r.type]=(byArea[a].types[r.type]||0)+1;
  });
  var html='<div class="card"><div class="card-title">рҹ—әпёҸ еҸ—еӣ° / жұӮеҠ©еҲҶдҪҲпјҲжңӘзөҗжЎҲпјү</div>'
    +'<div style="font-size:11px;color:var(--text4);margin-bottom:12px">дҫқйҖҡе ұдҪҚзҪ®й„үйҺ®еҪҷж•ҙпјҢдҫӣжҢҮжҸ®з«ҜеҲӨж–·зҶұеҚҖиҲҮиіҮжәҗжҠ•ж”ҫгҖӮеҜҰйҡӣ GIS ең–еұӨеҫ…жҺҘ NCDR / Google MapsгҖӮ</div>';
  var areas=Object.keys(byArea);
  if(!areas.length) html+='<div style="text-align:center;color:var(--text4);padding:20px">зӣ®еүҚз„ЎжңӘзөҗжЎҲжұӮеҠ©</div>';
  areas.sort(function(a,b){return byArea[b].count-byArea[a].count;}).forEach(function(a){
    var info=byArea[a], tlist=Object.keys(info.types).map(function(k){return k+'Г—'+info.types[k];}).join(' В· ');
    html+='<div style="display:flex;align-items:center;gap:12px;padding:12px;margin-bottom:8px;background:var(--bg2);border:1px solid var(--border);border-left:3px solid var(--red);border-radius:var(--r-sm)">'
      +'<div style="font-size:20px">рҹ“Қ</div><div style="flex:1"><div style="font-weight:700">'+a+'</div><div style="font-size:11px;color:var(--text4)">'+tlist+'</div></div>'
      +'<div style="text-align:right"><div style="font-size:18px;font-weight:800;color:var(--red)">'+info.count+'</div><div style="font-size:10px;color:var(--text4)">д»¶ В· '+info.people+' дәә</div></div></div>';
  });
  html+='</div>';
  return html;
}
