function reliefSimSubmit(){
  var tm=new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
  var newReq={id:'SOS-'+(2042+Math.floor(Math.random()*900)),time:tm,type:'зү©иіҮ',name:'ж°‘зңҫв—Ӣв—Ӣ',phone:'09**-***-'+Math.floor(100+Math.random()*899),location:'з«№еҙҺй„үпјҲжј”з·ҙжЁЎж“¬еЎ«е ұпјү',people:1+Math.floor(Math.random()*4),desc:'жј”з·ҙжЁЎж“¬пјҡж°‘зңҫиҮӘдё»еЎ«е ұд№ӢжұӮеҠ©жЎҲд»¶',status:'еҫ…иҷ•зҗҶ',dup:false};
  DATA.relief_req.requests.unshift(newReq);
  logSys('info','гҖҗж°‘зңҫжұӮеҠ©гҖ‘ж”¶еҲ°ж–°жұӮеҠ©йҖҡе ұпјҲжј”з·ҙжЁЎж“¬еЎ«е ұпјү');
  toast('рҹҶҳ е·Іж”¶еҲ°дёҖзӯҶж°‘зңҫжұӮеҠ© вҶ’ и«ӢиҮіж”¶д»¶еҢЈиҷ•зҗҶ');
  if(typeof loaHook==='function') loaHook('staff','рҹҶҳ ж–°жұӮеҠ©йҖҡе ұ\n'+newReq.id+' ('+newReq.type+')\nең°й»һпјҡ'+newReq.location+'\nдәәж•ёпјҡ'+newReq.people+'дәә\nи«ӢзӣЎйҖҹиҷ•зҗҶпјҒ');
  setReliefTab('inbox'); saveData();
}

