  COORD_TAB=t;
  ['match','partner','zone'].forEach(function(x){var b=document.getElementById('cotab-'+x);if(b)b.className='btn '+(x===t?'btn-blue':'btn-ghost');});
  var tid=document.getElementById('res-coord')?'res-coord':'coord-content';
