    +'<table class="tbl"><thead><tr><th>жҲ‘ж–№йңҖжұӮ</th><th>жҷӮйҷҗ</th><th>еҸҜеӘ’еҗҲдҫҶжәҗ</th><th>зӢҖж…Ӣ</th><th>ж“ҚдҪң</th></tr></thead><tbody>';
