      +'<td>'+(m.status==='еҫ…еӘ’еҗҲ'?'<button class="btn btn-blue btn-xs" onclick="coordMatch('+i+')">рҹӨқ зўәиӘҚеӘ’еҗҲ</button>':'<span style="font-size:9px;color:var(--text4)">вң“ е·Іе°ҚжҺҘ</span>')+'</td></tr>';
