function logPersonsMeal(){
  var bento=DATA.field&&DATA.field.supplies?DATA.field.supplies.find(function(x){return x.item==='дҫҝз•¶';}):null;
  if(bento&&bento.stock<50){toast('вҡ  дҫҝз•¶еә«еӯҳдёҚи¶і 50 д»Ҫ');logSys('warn','дҫӣйӨҗзҷ»иЁҳеӨұж•—пјҡдҫҝз•¶еә«еӯҳдёҚи¶і');return;}
  if(bento){bento.stock-=50;bento.status=bento.stock<bento.need*0.3?'red':(bento.stock<bento.need?'amber':'green');}
  DATA.persons.careStats.fixedPointMeals+=50;
  DATA.persons.careLogs.unshift({type:'е®ҡй»һй—ңжҮ·',target:'жў…еұұеңӢе°Ҹж”¶е®№жүҖ',summary:'зҶұйЈҹдҫӣжҮү 50 д»ҪпјҢдҫҝз•¶еә«еӯҳеҗҢжӯҘжүЈжёӣ',recorder:'зі»зөұиҮӘеӢ•',caseId:''});
  if(DATA.care_rec){DATA.care_rec.stats.fixedPointMeals+=50;}
  renderPersons(); if(typeof renderField==='function') renderField(); if(typeof renderAlerts==='function') renderAlerts(); saveData();
  toast('рҹҚұ дҫӣйӨҗе·Ізҷ»иЁҳпјҢеә«еӯҳе·ІеҗҢжӯҘ');
}
