function advancePersonRebuild(i){
  var c=DATA.persons.cases[i], phases=DATA.persons.rebuildPhases;
  var idx=phases.indexOf(c.rebuildPhase);
  if(idx<phases.length-1){
    c.rebuildPhase=phases[idx+1];
    c.rebuildPct=c.rebuildPhase==='йҮҚе»әе®ҢжҲҗ'?100:Math.min(95,Math.round((idx+2)/phases.length*100));
    var now=new Date(), ds=(now.getMonth()+1)+'-'+('0'+now.getDate()).slice(-2);
    c.timeline.push({type:'йҮҚе»әжҺЁйҖІ',summary:'йҡҺж®өжҺЁйҖІиҮігҖҢ'+c.rebuildPhase+'гҖҚ',recorder:'йҮҚе»әзө„',ts:ds});
    logSys('ok','гҖҗйҮҚе»әгҖ‘'+c.caseId+' жҺЁйҖІиҮігҖҢ'+c.rebuildPhase+'гҖҚ');
    toast('в–¶ '+c.caseId+' вҶ’ '+c.rebuildPhase); renderPersons(); saveData();
  }
}
function referPersonPsych(i){
  var c=DATA.persons.cases[i];
  c.psych='е·ІиҪүд»ӢиҝҪи№Ө'; c.longCare=true;
  var now=new Date(), ds=(now.getMonth()+1)+'-'+('0'+now.getDate()).slice(-2);
  c.timeline.push({type:'еҝғзҗҶиҝҪи№Ө',summary:'иҪүд»Ӣе°ҲжҘӯеҝғзҗҶеё«пјҢзҙҚе…Ҙй•·жңҹйҷӘдјҙ',recorder:'еҝғзҗҶйҮҚе»әзө„',ts:ds});
  logSys('warn','гҖҗеҝғзҗҶйҮҚе»әгҖ‘'+c.caseId+' е·ІиҪүд»Ӣе°ҲжҘӯеҝғзҗҶеё«');
  toast('рҹ©ә е·ІиҪүд»ӢеҝғзҗҶеё«пјҡ'+c.caseId); renderPersons(); saveData();
}

