function rebuildSchedule(i){
  var h=DATA.rebuild.households[i];
  var tmr=new Date(Date.now()+86400000), ds=(tmr.getMonth()+1)+'-'+('0'+tmr.getDate()).slice(-2);
  h.lastVisit=ds;
  if(DATA.care_rec&&DATA.care_rec.logs){
    DATA.care_rec.logs.unshift({type:'иЁӘиҰ–й—ңжҮ·',target:h.name+'пјҲ'+h.addr+'пјү',summary:'зҒҪеҫҢйҮҚе»әй•·жңҹйҷӘдјҙиЁӘиҰ–е·ІжҺ’е®ҡпјҲ'+h.phase+'пјү',recorder:'йҮҚе»әе°ҲжЎҲ'});
    if(DATA.care_rec.stats) DATA.care_rec.stats.visit++;
  }
  logSys('ok','гҖҗзҒҪеҫҢйҮҚе»әгҖ‘'+h.caseId+' е·ІжҺ’е®ҡй•·жңҹй—ңжҮ·иЁӘиҰ– вҶ’ еҗҢжӯҘй—ңжҮ·иЎҢеӢ•зҙҖйҢ„');
  toast('рҹ“… е·ІжҺ’иЁӘиҰ–дёҰеҗҢжӯҘй—ңжҮ·зҙҖйҢ„'); renderRebuild(); saveData();
}
