    it.status='е·Іе®ҢжҲҗ';
    DATA.care_rec.logs.unshift({type:'иЁӘиҰ–й—ңжҮ·',target:it.name+'пјҲ'+it.address.substring(0,6)+'вҖҰпјү',summary:'еҖӢжЎҲиЁӘиҰ–е®ҢжҲҗпјҢ'+it.route+' GPS и»Ңи·Ўе·Іеӯҳ',recorder:'зі»зөұиҮӘеӢ•'});
