function logMeal(){
  var bento=DATA.field.supplies.find(function(x){return x.item==='дҫҝз•¶';});
  if(bento&&bento.stock<50){toast('вҡ  дҫҝз•¶еә«еӯҳдёҚи¶і 50 д»ҪпјҢи«Ӣе…ҲиЈңиІЁжҲ–иӘҝж’Ҙ');logSys('warn','дҫӣйӨҗзҷ»иЁҳеӨұж•—пјҡдҫҝз•¶еә«еӯҳ '+bento.stock+' < 50');return;}
  if(bento){bento.stock-=50;bento.status=bento.stock<bento.need*0.3?'red':(bento.stock<bento.need?'amber':'green');}
  DATA.care_rec.stats.fixedPointMeals+=50;
  DATA.care_rec.logs.unshift({type:'е®ҡй»һй—ңжҮ·',target:'жў…еұұеңӢе°Ҹж”¶е®№жүҖ',summary:'зҶұйЈҹдҫӣжҮү 50 д»ҪпјҢдҫҝз•¶еә«еӯҳеҗҢжӯҘжүЈжёӣ',recorder:'зі»зөұиҮӘеӢ•'});
  renderCareRec();renderField();renderAlerts();saveData();
  logSys('ok','гҖҗдҫӣйӨҗгҖ‘е®ҡй»һдҫӣйӨҗ +50 вҶ’ й—ңжҮ·зөұиЁҲжӣҙж–°пјҢдҫҝз•¶еә«еӯҳ -50пјҲеү© '+(bento?bento.stock:0)+'пјү');
  toast('рҹҚұ дҫӣйӨҗе·Ізҷ»иЁҳпјҢеә«еӯҳе·ІеҗҢжӯҘ');
}
