var NEEDS_TAB = 'people';
function setNeedsTab(t){
  NEEDS_TAB = t;
  ['people','kitchen','survey','medical'].forEach(function(x){
    var b=document.getElementById('needtab-'+x);
    if(b) b.className='btn '+(x===t?'btn-blue':'btn-ghost');
  });
  renderNeeds();
}
function renderNeeds(){
  var el=document.getElementById('needs-content'); if(!el) return;
  var loa='<div style="font-size:11px;color:var(--text4);background:var(--bg3);border-radius:6px;padding:6px 10px;margin-bottom:12px">рҹ“ұ е…ҘеҸЈпјҡеҝ—е·ҘйҖҸйҒҺ <strong>Line OA</strong> еӣһе ұ вҶ’ иҮӘеӢ•йҖІе…Ҙе°ҚжҮүйҖҡе ұжұ  вҶ’ е№№йғЁж”¶д»¶ вҶ’ иҪүжҙҫеҚіжҷӮиӘҝеәҰдёӯеҸ°</div>';
  if(NEEDS_TAB==='people'){
    el.innerHTML=loa+subTabBar([
      {id:'inbox',btnId:'rrtab-inbox',label:'рҹ“Ҙ ж”¶д»¶еҢЈ',  fn:"setReliefTab('inbox')"},
      {id:'map',  btnId:'rrtab-map',  label:'рҹ—әпёҸ еҲҶдҪҲең–', fn:"setReliefTab('map')"},
      {id:'form', btnId:'rrtab-form', label:'рҹ“ұ еЎ«е ұй җиҰҪ',fn:"setReliefTab('form')"},
    ], RELIEF_TAB||'inbox')+'<div id="needs-relief-content"></div>';
    renderReliefReq('needs-relief-content');
  } else if(NEEDS_TAB==='kitchen'){
    el.innerHTML=loa+renderNeedsKitchen();
  } else if(NEEDS_TAB==='survey'){
    el.innerHTML=loa+renderNeedsSurvey();
  } else if(NEEDS_TAB==='medical'){
    el.innerHTML=loa+renderNeedsMedical();
  }
}
