function addNeedsKitchen(){
  var item=prompt('йңҖжұӮе“Ғй …пјҡ');
  if(!item) return;
  var qty=prompt('ж•ёйҮҸпјҡ');
  var site=prompt('з«ҷй»һеҗҚзЁұпјҡ');
  var newId='KN-'+(DATA.needs.kitchen.length+1).toString().padStart(3,'0');
  DATA.needs.kitchen.unshift({id:newId, time:new Date().toLocaleString('zh-TW',{hour:'2-digit',minute:'2-digit'}), site:site||'зҸҫе ҙ', item:item, qty:qty||'иӢҘе№І', urgency:'P2', status:'еҫ…й…ҚйҖҒ', reporter:'е№№йғЁ'});
  renderNeeds();
  toast('вң… е»ҡжҲҝйңҖжұӮ '+newId+' е·Іж–°еўһ');
  if(typeof loaHook==='function') loaHook('staff','рҹҚұ е»ҡжҲҝж–°йңҖжұӮ\n'+newId+' '+item+' '+qty+'\nз«ҷй»һпјҡ'+(site||'зҸҫе ҙ')+'\nйңҖзӣЎеҝ«й…ҚйҖҒ');
}

