// в”Җв”Җ жүӢж©ҹеҒҙж¬„ж»‘еӢ•жүӢеӢў в”Җв”Җ
(function(){
  var touchStartX=0, touchStartY=0, tracking=false, fromEdge=false, insideNav=false;
  var EDGE=24, THRESHOLD=55;
  document.addEventListener('touchstart',function(e){
    if(window.innerWidth>768) return;
    var t=e.touches[0];
    touchStartX=t.clientX; touchStartY=t.clientY;
    var navOpen=document.body.classList.contains('nav-open');
    var nav=document.getElementById('nav');
    insideNav=(navOpen && nav && nav.contains(e.target));
    tracking=true;
    fromEdge=(touchStartX<=EDGE);
    if(!fromEdge && !navOpen) tracking=false;
  },{passive:true});
  document.addEventListener('touchend',function(e){
    if(!tracking||window.innerWidth>768){ tracking=false; return; }
    tracking=false;
    var t=e.changedTouches[0];
    var dx=t.clientX-touchStartX;
    var dy=Math.abs(t.clientY-touchStartY);
    var navOpen=document.body.classList.contains('nav-open');
    // еңЁеҒҙж¬„е…§йғЁпјҡеҸӘжңүж°ҙе№ідҪҚз§»йҒ еӨ§ж–јеһӮзӣҙжҷӮжүҚж”¶еҗҲпјҢеҗҰеүҮиҰ–зӮәжҚІеӢ•
    if(insideNav){
      if(dx<-THRESHOLD && Math.abs(dx)>dy*1.8){ document.body.classList.remove('nav-open'); }
      return;
    }
    if(dy>Math.abs(dx)) return;
    if(fromEdge && dx>THRESHOLD && !navOpen){
      document.body.classList.add('nav-open');
    } else if(navOpen && dx<-THRESHOLD){
      document.body.classList.remove('nav-open');
    }
  },{passive:true});
  document.addEventListener('click',function(e){
    if(window.innerWidth>768) return;
    if(!document.body.classList.contains('nav-open')) return;
    var nav=document.getElementById('nav');
    var toggleBtn=e.target.closest('.nav-collapse-btn');
    if(nav && !nav.contains(e.target) && !toggleBtn){
      document.body.classList.remove('nav-open');
    }
  });
})();
